// 简单的 HTTP 响应结构
@interface TVNCHttpResponse : NSObject
@property (nonatomic, assign) NSInteger statusCode;
@property (nonatomic, copy) NSString *contentType;
@property (nonatomic, copy) NSData *body;
@end

@implementation TVNCHttpResponse
@end

// HTTP 连接处理
@interface TVNCHttpConnection : NSObject
@property (nonatomic, assign) int clientSocket;
@property (nonatomic, strong) TVNCHttpServer *server;
@property (nonatomic, strong) NSDictionary<NSString *, NSString *> *parsedHeaders;
- (void)handle;
@end

@interface TVNCHttpServer () {
    int _serverSocket;
    BOOL _running;
    BOOL _webdavEnabled;
    NSString *_webdavRootPath;
    dispatch_queue_t _serverQueue;
    
    // 群控 WebSocket 相关
    int _wsServerSocket;
    BOOL _wsRunning;
    NSMutableArray<NSNumber *> *_wsClientSockets;
    NSMutableDictionary<NSNumber *, NSString *> *_wsClientIPs; // sock → clientIP
    dispatch_queue_t _wsServerQueue;
    BOOL _groupMasterEnabled;
    NSUInteger _groupWSPort;
    
    // 从控模式：连接到主控
    int _masterSocket;
    BOOL _masterConnected;
    NSString *_masterIP;
    NSUInteger _masterPort;
    dispatch_queue_t _masterQueue;

    // 电脑中继模式 (Relay Mode)
    BOOL _relayModeEnabled;
    BOOL _relayConnected;
    int _relaySocket;
    NSString *_relayIP;
    NSUInteger _relayPort;
    NSString *_relayRole;  // "master" or "slave"
    BOOL _isInjectingTouchEvent;  // 防回环标志
    dispatch_queue_t _relayQueue;
    
    // 屏幕尺寸缓存（避免每次 executeGroupTouchEvent 都读 UIScreen）
    CGFloat _cachedScreenWidth;   // 像素宽
    CGFloat _cachedScreenHeight;  // 像素高
    UIInterfaceOrientation _cachedOrientation; // 上次缓存时的方向
}
@end

@implementation TVNCHttpServer

@synthesize webdavEnabled = _webdavEnabled;
@synthesize webdavRootPath = _webdavRootPath;

// 辅助函数：直接读 plist 文件，绕过 CFPreferences 缓存问题
static NSString *TVNCPreferencesPlistPath(void) {
    NSString *bundleId = [[NSBundle mainBundle] bundleIdentifier];
    if (!bundleId || [bundleId length] == 0) {
        bundleId = @"com.82flex.trollvnc"; // fallback
    }
    return [@"/var/mobile/Library/Preferences/" stringByAppendingPathComponent:[bundleId stringByAppendingString:@".plist"]];
}

static NSString *TVNCPreferencesAppId(void) {
    NSString *bundleId = [[NSBundle mainBundle] bundleIdentifier];
    if (!bundleId || [bundleId length] == 0) {
        bundleId = @"com.82flex.trollvnc"; // fallback
    }
    return bundleId;
}

static BOOL TVNCReadBool(CFStringRef key) {
    // 方法1：直接读 plist 文件（最可靠）
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSDictionary *dict = [NSDictionary dictionaryWithContentsOfFile:plistPath];
    if (dict) {
        NSString *keyStr = (__bridge NSString *)key;
        id value = dict[keyStr];
        if (value) {
            if ([value isKindOfClass:[NSNumber class]]) {
                return [value boolValue];
            } else if ([value isKindOfClass:[NSString class]]) {
                return [value boolValue];
            }
        }
    }
    // 方法2：fallback 到 CFPreferences
    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
    CFPropertyListRef value = CFPreferencesCopyAppValue(key, (__bridge CFStringRef)appId);
    if (value) {
        BOOL b = [(NSNumber *)CFBridgingRelease(value) boolValue];
        return b;
    }
    return NO;
}

// 辅助函数：同时写 plist 文件和 CFPreferences，确保立即生效
static void TVNCWriteBool(CFStringRef key, BOOL value) {
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSMutableDictionary *dict = [NSMutableDictionary dictionaryWithContentsOfFile:plistPath];
    if (!dict) {
        dict = [NSMutableDictionary dictionary];
    }
    dict[(__bridge NSString *)key] = @(value);
    [dict writeToFile:plistPath atomically:YES];

    // 同时同步到 CFPreferences
    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesSetAppValue(key, value ? kCFBooleanTrue : kCFBooleanFalse, (__bridge CFStringRef)appId);
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
}

// 辅助函数：读取字符串型偏好设置
static NSString *TVNCReadString(CFStringRef key, NSString *defaultValue) {
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSDictionary *dict = [NSDictionary dictionaryWithContentsOfFile:plistPath];
    if (dict) {
        NSString *keyStr = (__bridge NSString *)key;
        id value = dict[keyStr];
        if ([value isKindOfClass:[NSString class]] && [(NSString *)value length] > 0) {
            return (NSString *)value;
        }
    }
    // fallback CFPreferences
    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
    CFPropertyListRef value = CFPreferencesCopyAppValue(key, (__bridge CFStringRef)appId);
    if (value) {
        NSString *s = (__bridge_transfer NSString *)value;
        if ([s isKindOfClass:[NSString class]] && s.length > 0) return s;
    }
    return defaultValue;
}

// 辅助函数：写入字符串型偏好设置
static void TVNCWriteString(CFStringRef key, NSString *value) {
    NSString *plistPath = TVNCPreferencesPlistPath();
    NSMutableDictionary *dict = [NSMutableDictionary dictionaryWithContentsOfFile:plistPath];
    if (!dict) {
        dict = [NSMutableDictionary dictionary];
    }
    if (value) {
        dict[(__bridge NSString *)key] = value;
    } else {
        [dict removeObjectForKey:(__bridge NSString *)key];
    }
    [dict writeToFile:plistPath atomically:YES];

    NSString *appId = TVNCPreferencesAppId();
    CFPreferencesSetAppValue(key, (__bridge CFStringRef)value, (__bridge CFStringRef)appId);
    CFPreferencesAppSynchronize((__bridge CFStringRef)appId);
}

// 辅助函数：读取 app 的偏好设置
static NSUserDefaults *TVNCGetDefaults(void) {
    static NSUserDefaults *sDefaults = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        NSString *bundleId = [[NSBundle mainBundle] bundleIdentifier];
        if (!bundleId || [bundleId length] == 0) {
            bundleId = @"com.82flex.trollvnc";
        }
        sDefaults = [[NSUserDefaults alloc] initWithSuiteName:bundleId];
    });
    return sDefaults;
}

// 辅助函数：使用 popen 执行命令并获取输出
- (NSString *)executeCommand:(NSString *)command {
    FILE *fp = popen([command UTF8String], "r");
    if (fp == NULL) {
        return nil;
    }
    
    char buffer[256];
    NSMutableString *output = [NSMutableString string];
    while (fgets(buffer, sizeof(buffer), fp) != NULL) {
        [output appendString:[NSString stringWithUTF8String:buffer]];
    }
    pclose(fp);
    
    return [output stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
}

// 辅助函数：使用 popen 执行命令（无输出）
- (BOOL)runCommand:(NSString *)command {
    FILE *fp = popen([command UTF8String], "r");
    if (fp == NULL) {
        return NO;
    }
    pclose(fp);
    return YES;
}

+ (instancetype)sharedServer {
    static TVNCHttpServer *_inst = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        _inst = [[self alloc] init];
    });
    return _inst;
}

- (instancetype)init {
    if (self = [super init]) {
        _port = 8182;
        _serverSocket = -1;
        _running = NO;
        _webdavEnabled = TVNCReadBool(CFSTR("WebDAVEnabled"));
        _webdavRootPath = @"/";  // 固定为根目录，访问所有目录
        _serverQueue = dispatch_queue_create("com.trollvnc.httpserver", DISPATCH_QUEUE_SERIAL);
        
        // 群控 WebSocket 初始化
        _wsServerSocket = -1;
        _wsRunning = NO;
        _wsClientSockets = [NSMutableArray array];
        _wsClientIPs = [NSMutableDictionary dictionary];
        _wsServerQueue = dispatch_queue_create("com.trollvnc.wsserver", DISPATCH_QUEUE_SERIAL);
        _groupMasterEnabled = NO;
        _groupWSPort = 8183;
        
        // 从控模式初始化
        _masterSocket = -1;
        _masterConnected = NO;
        _masterIP = nil;
        _masterPort = 8183;
        _masterQueue = dispatch_queue_create("com.trollvnc.masterclient", DISPATCH_QUEUE_SERIAL);

        // 中继模式初始化
        _relayModeEnabled = NO;
        _relayConnected = NO;
        _relaySocket = -1;
        _relayIP = nil;
        _relayPort = 8183;
        _relayRole = nil;
        _isInjectingTouchEvent = NO;
        _relayQueue = dispatch_queue_create("com.trollvnc.relay", DISPATCH_QUEUE_SERIAL);
    }
    return self;
}

- (BOOL)isRunning {
    return _running;
}

- (BOOL)startServer {
    if (_running) {
        return YES;
    }
    
    // 创建 socket
    _serverSocket = socket(AF_INET, SOCK_STREAM, 0);
    if (_serverSocket < 0) {
        TVLog(@"HTTP Server: Failed to create socket");
        return NO;
    }
    
    // 允许地址重用
    int opt = 1;
    setsockopt(_serverSocket, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
    
    // 绑定地址
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons((uint16_t)_port);
    
    if (bind(_serverSocket, (struct sockaddr *)&addr, sizeof(addr)) < 0) {
        TVLog(@"HTTP Server: Failed to bind to port %lu", (unsigned long)_port);
        close(_serverSocket);
        _serverSocket = -1;
        return NO;
    }
    
    // 开始监听
    if (listen(_serverSocket, 10) < 0) {
        TVLog(@"HTTP Server: Failed to listen");
        close(_serverSocket);
        _serverSocket = -1;
        return NO;
    }
    
    _running = YES;
    TVLog(@"HTTP Server: Started on port %lu", (unsigned long)_port);
    
    // 在后台队列接受连接
    dispatch_async(_serverQueue, ^{
        [self acceptConnections];
    });
    
    return YES;
}

- (void)stopServer {
    if (!_running) {
        return;
    }
    
    _running = NO;
    
    if (_serverSocket >= 0) {
        close(_serverSocket);
        _serverSocket = -1;
    }
    
    // 同时停止群控 WebSocket 服务器
    [self stopGroupWebSocketServer];
    
    TVLog(@"HTTP Server: Stopped");
}

- (void)acceptConnections {
    while (_running) {
        struct sockaddr_in clientAddr;
        socklen_t addrLen = sizeof(clientAddr);
        
        int clientSocket = accept(_serverSocket, (struct sockaddr *)&clientAddr, &addrLen);
        if (clientSocket < 0) {
            if (_running) {
                TVLog(@"HTTP Server: Accept failed");
            }
            continue;
        }
        
        // 在全局队列处理连接
        dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
            TVNCHttpConnection *conn = [[TVNCHttpConnection alloc] init];
            conn.clientSocket = clientSocket;
            conn.server = self;
            [conn handle];
        });
    }
}

// 处理 HTTP 请求并返回响应
- (TVNCHttpResponse *)handleRequest:(NSString *)method 
                                 path:(NSString *)path 
                                query:(NSDictionary *)query 
                                 body:(nullable NSData *)body 
                           clientAddr:(nullable NSString *)clientAddr
                             headers:(nullable NSDictionary<NSString *, NSString *> *)headers {
    
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    // 处理 OPTIONS 请求（CORS 预检）
    if ([method isEqualToString:@"OPTIONS"]) {
        response.statusCode = 200;
        response.contentType = @"text/plain";
        response.body = [@"OK" dataUsingEncoding:NSUTF8StringEncoding];
        return response;
    }
    
    // WebDAV 浏览器界面（GET /webdav 或 /webdav/）
    if (TVNCReadBool(CFSTR("WebDAVEnabled")) && [method isEqualToString:@"GET"]) {
        if ([path isEqualToString:@"/webdav"] || [path isEqualToString:@"/webdav/"]) {
            return [self handleWebDAVUI];
        }
    }
    
    // WebDAV 处理（路径以 /webdav 开头且已启用）
    if (TVNCReadBool(CFSTR("WebDAVEnabled")) && [path hasPrefix:@"/webdav"]) {
        return [self handleWebDAV:method path:path query:query body:body headers:headers];
    }
    
    // API 路由处理
    if ([path isEqualToString:@"/api/screenshot"]) {
        return [self handleScreenshot:query];
    } else if ([path isEqualToString:@"/api/screenshot/fast"]) {
        return [self handleScreenshotFast:query];
    } else if ([path isEqualToString:@"/api/stream.mjpeg"]) {
        return [self handleStreamMjpeg:query];
    } else if ([path isEqualToString:@"/api/writefile_text"]) {
        return [self handleWriteFileText:query body:body];
    } else if ([path isEqualToString:@"/api/clipboard"]) {
        if ([method isEqualToString:@"GET"]) {
            return [self handleClipboardGet:query];
        } else {
            return [self handleClipboard:query body:body];
        }
    } else if ([path isEqualToString:@"/api/clipboard_text"]) {
        if ([method isEqualToString:@"GET"]) {
            return [self handleClipboardTextGet:query];
        } else {
            return [self handleClipboardText:query body:body];
        }
    } else if ([path isEqualToString:@"/api/input"]) {
        return [self handleInput:query body:body];
    } else if ([path isEqualToString:@"/api/key"]) {
        return [self handleKey:query];
    } else if ([path isEqualToString:@"/api/clients"]) {
        return [self handleClients];
    } else if ([path isEqualToString:@"/api/status"]) {
        return [self handleStatus];
    } else if ([path isEqualToString:@"/api/device"]) {
        return [self handleDeviceInfo:query clientAddr:clientAddr];
    } else if ([path isEqualToString:@"/api/checkfile"]) {
        return [self handleCheckFile];
    } else if ([path isEqualToString:@"/api/upload"]) {
        return [self handleUploadFile:query body:body];
    } else if ([path isEqualToString:@"/api/volume"]) {
        return [self handleVolume:query body:body];
    } else if ([path isEqualToString:@"/api/brightness"]) {
        return [self handleBrightness:query body:body];
    } else if ([path isEqualToString:@"/api/reboot"]) {
        return [self handleReboot];
    } else if ([path isEqualToString:@"/api/respring"]) {
        return [self handleRespring];
    } else if ([path isEqualToString:@"/api/screen/lock"]) {
        return [self handleScreenLock];
    } else if ([path isEqualToString:@"/api/screen/unlock"]) {
        return [self handleScreenUnlock];
    } else if ([path isEqualToString:@"/api/home"]) {
        return [self handleHome];
    } else if ([path isEqualToString:@"/api/taskmanager"]) {
        return [self handleTaskManager];
    } else if ([path isEqualToString:@"/test"]) {
        return [self handleTestInterface];
    } else if ([path isEqualToString:@"/api/filelist"]) {
        return [self handleFileList:query];
    } else if ([path isEqualToString:@"/api/readfile"]) {
        return [self handleReadFile:query];
    } else if ([path isEqualToString:@"/api/deletefile"]) {
        return [self handleDeleteFile:query];
    } else if ([path isEqualToString:@"/api/createfolder"]) {
        return [self handleCreateFolder:query];
    } else if ([path isEqualToString:@"/api/webdav/start"]) {
        return [self handleWebDAVStart:query];
    } else if ([path isEqualToString:@"/api/webdav/stop"]) {
        return [self handleWebDAVStop];
    } else if ([path isEqualToString:@"/api/webdav/status"]) {
        return [self handleWebDAVStatus];
    } else if ([path isEqualToString:@"/api/install/tipa"]) {
        return [self handleInstallTipa:query];
    } else if ([path isEqualToString:@"/api/install/url"]) {
        return [self handleInstallUrl:query];
    } else if ([path isEqualToString:@"/api/install/deb"]) {
        return [self handleInstallDeb:query body:body];
    } else if ([path isEqualToString:@"/api/plist"]) {
        return [self handlePlist:method query:query body:body];
    } else if ([path isEqualToString:@"/api/network/static_ip"]) {
        return [self handleNetworkStaticIP:body];
    } else if ([path isEqualToString:@"/api/group/start"]) {
        return [self handleGroupStart:query];
    } else if ([path isEqualToString:@"/api/group/stop"]) {
        return [self handleGroupStop];
    } else if ([path isEqualToString:@"/api/group/status"]) {
        return [self handleGroupStatus];
    } else if ([path isEqualToString:@"/api/group/touch"]) {
        return [self handleGroupTouch:body];
    } else if ([path isEqualToString:@"/api/group/connect"]) {
        return [self handleGroupConnect:query];
    } else if ([path isEqualToString:@"/api/group/disconnect"]) {
        return [self handleGroupDisconnect];
    } else if ([path isEqualToString:@"/api/group/relay/start"]) {
        return [self handleRelayStart:query];
    } else if ([path isEqualToString:@"/api/group/relay/stop"]) {
        return [self handleRelayStop];
    } else if ([path isEqualToString:@"/api/group/slaves"]) {
        return [self handleGroupSlaves];
    } else if ([path isEqualToString:@"/api/group/proxy-screenshot"]) {
        return [self handleGroupProxyScreenshot:query];
    } else if ([path isEqualToString:@"/api/alert"]) {
        return [self handleAlert:query];
    } else if ([path isEqualToString:@"/group-test"]) {
        return [self handleGroupTestPage];
    } else if ([path isEqualToString:@"/group-control"]) {
        return [self handleGroupControlPage];
    } else if ([path isEqualToString:@"/"]) {
        // 返回简单的 API 文档
        return [self handleRoot];
    }
    
    // 404 Not Found
    response.statusCode = 404;
    response.contentType = @"application/json";
    NSDictionary *error = @{@"error": @"Not Found", @"path": path};
    response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
    return response;
}

#pragma mark - WebDAV Handlers

// 将 URL 路径转换为文件系统路径
- (NSString *)webdavFilePathForPath:(NSString *)path {
    // path 格式: /webdav/xxx，去掉 /webdav 前缀
    // /webdav = 7 chars, /webdav/ = 8 chars
    if (path.length <= 8) {
        return self.webdavRootPath;
    }
    NSString *relativePath = [path substringFromIndex:8]; // 去掉 "/webdav"
    // 解码 URL 百分号编码（中文路径如 %E8%B5%84%E6%BA%90 → 资源）
    relativePath = [relativePath stringByRemovingPercentEncoding];
    if (relativePath.length == 0 || [relativePath isEqualToString:@"/"]) {
        return self.webdavRootPath;
    }
    // 去掉开头的 /
    if ([relativePath hasPrefix:@"/"]) {
        relativePath = [relativePath substringFromIndex:1];
    }
    return [self.webdavRootPath stringByAppendingPathComponent:relativePath];
}

// 生成 PROPFIND 响应的 XML
- (NSString *)generatePropfindXMLForPath:(NSString *)filePath isDirectory:(BOOL)isDir {
    NSFileManager *fm = [NSFileManager defaultManager];
    NSDictionary *attrs = [fm attributesOfItemAtPath:filePath error:nil];
    NSDate *modDate = attrs[NSFileModificationDate];
    NSNumber *fileSize = attrs[NSFileSize];
    
    NSDateFormatter *df = [[NSDateFormatter alloc] init];
    [df setDateFormat:@"yyyy-MM-dd'T'HH:mm:ss'Z'"];
    [df setTimeZone:[NSTimeZone timeZoneWithAbbreviation:@"UTC"]];
    NSString *modDateStr = [df stringFromDate:modDate ?: [NSDate date]];
    
    NSString *displayName = [filePath lastPathComponent];
    if (!displayName || displayName.length == 0) {
        displayName = @"/";
    }
    
    NSMutableString *xml = [NSMutableString string];
    [xml appendString:@"<?xml version=\"1.0\" encoding=\"utf-8\"?>\n"];
    [xml appendString:@"<D:multistatus xmlns:D=\"DAV:\">\n"];
    
    // 当前路径的响应
    [xml appendString:@"  <D:response>\n"];
    // href 必须是相对于 WebDAV 根的路径（带前导 /）
    NSString *root = self.webdavRootPath;
    NSString *relativePath = filePath;
    if ([filePath hasPrefix:root]) {
        relativePath = [filePath substringFromIndex:root.length];
    }
    if (relativePath.length == 0 || [relativePath isEqualToString:@"/"]) {
        relativePath = @"/";
    } else if (![relativePath hasPrefix:@"/"]) {
        relativePath = [@"/" stringByAppendingString:relativePath];
    }
    NSString *hrefPath = relativePath;
    if (![hrefPath hasPrefix:@"/"]) hrefPath = [@"/" stringByAppendingString:hrefPath];
    // href 中的路径必须做 URL 编码（中文等非 ASCII 字符需要编码）
    NSString *encodedHrefPath = [hrefPath stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLPathAllowedCharacterSet]];
    [xml appendFormat:@"    <D:href>%@</D:href>\n", encodedHrefPath ?: hrefPath];
    [xml appendString:@"    <D:propstat>\n"];
    [xml appendString:@"      <D:prop>\n"];
    [xml appendFormat:@"        <D:displayname>%@</D:displayname>\n", displayName];
    [xml appendFormat:@"        <D:getlastmodified>%@</D:getlastmodified>\n", modDateStr];
    if (!isDir) {
        [xml appendFormat:@"        <D:getcontentlength>%@</D:getcontentlength>\n", fileSize ?: @"0"];
        [xml appendString:@"        <D:getcontenttype>application/octet-stream</D:getcontenttype>\n"];
    } else {
        [xml appendString:@"        <D:resourcetype><D:collection/></D:resourcetype>\n"];
    }
    [xml appendString:@"      </D:prop>\n"];
    [xml appendString:@"      <D:status>HTTP/1.1 200 OK</D:status>\n"];
    [xml appendString:@"    </D:propstat>\n"];
    [xml appendString:@"  </D:response>\n"];
    
    // 如果是目录，列出子项
    if (isDir) {
        NSArray *subitems = [fm contentsOfDirectoryAtPath:filePath error:nil];
        for (NSString *item in subitems) {
            NSString *itemPath = [filePath stringByAppendingPathComponent:item];
            BOOL itemIsDir = NO;
            [fm fileExistsAtPath:itemPath isDirectory:&itemIsDir];
            NSDictionary *itemAttrs = [fm attributesOfItemAtPath:itemPath error:nil];
            NSDate *itemModDate = itemAttrs[NSFileModificationDate];
            NSNumber *itemSize = itemAttrs[NSFileSize];
            NSString *itemModStr = [df stringFromDate:itemModDate ?: [NSDate date]];
            
            [xml appendString:@"  <D:response>\n"];
            NSString *itemRelativePath = itemPath;
            if ([itemPath hasPrefix:root]) {
                itemRelativePath = [itemPath substringFromIndex:root.length];
            }
            if (itemRelativePath.length == 0 || [itemRelativePath isEqualToString:@"/"]) {
                itemRelativePath = @"/";
            } else if (![itemRelativePath hasPrefix:@"/"]) {
                itemRelativePath = [@"/" stringByAppendingString:itemRelativePath];
            }
            NSString *itemHref = itemRelativePath;
            // href 中的路径必须做 URL 编码（中文等非 ASCII 字符需要编码）
            NSString *encodedItemHref = [itemHref stringByAddingPercentEncodingWithAllowedCharacters:[NSCharacterSet URLPathAllowedCharacterSet]];
            [xml appendFormat:@"    <D:href>%@</D:href>\n", encodedItemHref ?: itemHref];
            [xml appendString:@"    <D:propstat>\n"];
            [xml appendString:@"      <D:prop>\n"];
            [xml appendFormat:@"        <D:displayname>%@</D:displayname>\n", item];
            [xml appendFormat:@"        <D:getlastmodified>%@</D:getlastmodified>\n", itemModStr];
            if (!itemIsDir) {
                [xml appendFormat:@"        <D:getcontentlength>%@</D:getcontentlength>\n", itemSize ?: @"0"];
                [xml appendString:@"        <D:getcontenttype>application/octet-stream</D:getcontenttype>\n"];
            } else {
                [xml appendString:@"        <D:resourcetype><D:collection/></D:resourcetype>\n"];
            }
            [xml appendString:@"      </D:prop>\n"];
            [xml appendString:@"      <D:status>HTTP/1.1 200 OK</D:status>\n"];
            [xml appendString:@"    </D:propstat>\n"];
            [xml appendString:@"  </D:response>\n"];
        }
    }
    
    [xml appendString:@"</D:multistatus>"];
    return xml;
}

// 处理 WebDAV 请求
- (TVNCHttpResponse *)handleWebDAV:(NSString *)method path:(NSString *)path query:(NSDictionary *)query body:(NSData *)body headers:(NSDictionary *)headers {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    NSString *filePath = [self webdavFilePathForPath:path];
    
    TVLog(@"WebDAV: %@ %@", method, filePath);
    
    if ([method isEqualToString:@"PROPFIND"]) {
        // 列出目录或文件信息
        NSFileManager *fm = [NSFileManager defaultManager];
        BOOL isDir = NO;
        BOOL exists = [fm fileExistsAtPath:filePath isDirectory:&isDir];
        
        if (!exists) {
            // 如果路径不存在，尝试父目录
            NSString *parentDir = [filePath stringByDeletingLastPathComponent];
            BOOL parentIsDir = NO;
            if ([fm fileExistsAtPath:parentDir isDirectory:&parentIsDir] && parentIsDir) {
                // 返回父目录列表
                NSString *xml = [self generatePropfindXMLForPath:parentDir isDirectory:YES];
                response.statusCode = 207;
                response.contentType = @"application/xml; charset=utf-8";
                response.body = [xml dataUsingEncoding:NSUTF8StringEncoding];
                return response;
            }
            
            response.statusCode = 404;
            response.contentType = @"text/plain";
            response.body = [@"Not Found" dataUsingEncoding:NSUTF8StringEncoding];
            return response;
        }
        
        NSString *xml = [self generatePropfindXMLForPath:filePath isDirectory:isDir];
        response.statusCode = 207;
        response.contentType = @"application/xml; charset=utf-8";
        response.body = [xml dataUsingEncoding:NSUTF8StringEncoding];
        return response;
        
    } else if ([method isEqualToString:@"GET"]) {
        // 下载文件
        NSFileManager *fm = [NSFileManager defaultManager];
        BOOL isDir = NO;
        if ([fm fileExistsAtPath:filePath isDirectory:&isDir] && !isDir) {
            NSData *fileData = [NSData dataWithContentsOfFile:filePath];
            if (fileData) {
                response.statusCode = 200;
                response.contentType = @"application/octet-stream";
                response.body = fileData;
                return response;
            }
        }
        
        response.statusCode = 404;
        response.contentType = @"text/plain";
        response.body = [@"Not Found" dataUsingEncoding:NSUTF8StringEncoding];
        return response;
        
    } else if ([method isEqualToString:@"PUT"]) {
        // 上传文件
        NSString *dirPath = [filePath stringByDeletingLastPathComponent];
        NSFileManager *fm = [NSFileManager defaultManager];
        
        // 确保目录存在
        if (![fm fileExistsAtPath:dirPath]) {
            [fm createDirectoryAtPath:dirPath withIntermediateDirectories:YES attributes:nil error:nil];
        }
        
        BOOL success = [body writeToFile:filePath atomically:YES];
        if (success) {
            response.statusCode = 201;
            response.contentType = @"text/plain";
            response.body = [@"Created" dataUsingEncoding:NSUTF8StringEncoding];
        } else {
            response.statusCode = 500;
            response.contentType = @"text/plain";
            response.body = [@"Internal Server Error" dataUsingEncoding:NSUTF8StringEncoding];
        }
        return response;
        
    } else if ([method isEqualToString:@"DELETE"]) {
        // 删除文件或目录
        NSFileManager *fm = [NSFileManager defaultManager];
        NSError *error = nil;
        BOOL success = [fm removeItemAtPath:filePath error:&error];
        
        if (success) {
            response.statusCode = 204;
            response.contentType = @"text/plain";
            response.body = [@"No Content" dataUsingEncoding:NSUTF8StringEncoding];
        } else {
            response.statusCode = 500;
            response.contentType = @"text/plain";
            response.body = [[error localizedDescription] dataUsingEncoding:NSUTF8StringEncoding];
        }
        return response;
        
    } else if ([method isEqualToString:@"MKCOL"]) {
        // 创建目录
        NSFileManager *fm = [NSFileManager defaultManager];
        NSError *error = nil;
        BOOL success = [fm createDirectoryAtPath:filePath withIntermediateDirectories:YES attributes:nil error:&error];
        
        if (success) {
            response.statusCode = 201;
            response.contentType = @"text/plain";
            response.body = [@"Created" dataUsingEncoding:NSUTF8StringEncoding];
        } else {
            response.statusCode = 500;
            response.contentType = @"text/plain";
            response.body = [[error localizedDescription] dataUsingEncoding:NSUTF8StringEncoding];
        }
        return response;
        
    } else if ([method isEqualToString:@"MOVE"]) {
        // 移动/重命名文件
        NSString *destination = headers[@"Destination"];
        if (!destination || destination.length == 0) {
            response.statusCode = 400;
            response.contentType = @"text/plain";
            response.body = [@"Missing Destination header" dataUsingEncoding:NSUTF8StringEncoding];
            return response;
        }

        // 解析 Destination URL，提取路径部分
        // Destination 可能是完整 URL（http://host/webdav/xxx）或绝对路径（/webdav/xxx）
        NSString *destPath = nil;
        if ([destination hasPrefix:@"/"]) {
            // 绝对路径
            destPath = destination;
        } else {
            // 完整 URL，提取路径部分
            NSURL *destURL = [NSURL URLWithString:destination];
            if (destURL) {
                destPath = destURL.path;
            }
        }

        if (!destPath || ![destPath hasPrefix:@"/webdav"]) {
            response.statusCode = 400;
            response.contentType = @"text/plain";
            response.body = [@"Invalid Destination header" dataUsingEncoding:NSUTF8StringEncoding];
            return response;
        }

        // 提取源和目标文件系统路径
        NSString *srcFilePath = filePath;
        NSString *dstFilePath = [self webdavFilePathForPath:destPath];
        NSString *overwrite = headers[@"Overwrite"];

        NSFileManager *fm = [NSFileManager defaultManager];
        BOOL srcExists = [fm fileExistsAtPath:srcFilePath];
        BOOL dstExists = [fm fileExistsAtPath:dstFilePath];

        if (!srcExists) {
            response.statusCode = 404;
            response.contentType = @"text/plain";
            response.body = [@"Source not found" dataUsingEncoding:NSUTF8StringEncoding];
            return response;
        }

        if (dstExists && ![overwrite isEqualToString:@"T"]) {
            response.statusCode = 412;
            response.contentType = @"text/plain";
            response.body = [@"Destination already exists" dataUsingEncoding:NSUTF8StringEncoding];
            return response;
        }

        NSError *error = nil;
        BOOL success = NO;

        // 如果目标存在，先删除
        if (dstExists) {
            success = [fm removeItemAtPath:dstFilePath error:&error];
            if (!success) {
                response.statusCode = 500;
                response.contentType = @"text/plain";
                response.body = [[error localizedDescription] dataUsingEncoding:NSUTF8StringEncoding];
                return response;
            }
        }

        // 执行移动
        success = [fm moveItemAtPath:srcFilePath toPath:dstFilePath error:&error];
        if (success) {
            response.statusCode = dstExists ? 204 : 201;
            response.contentType = @"text/plain";
            response.body = [@"Moved" dataUsingEncoding:NSUTF8StringEncoding];
        } else {
            response.statusCode = 500;
            response.contentType = @"text/plain";
            response.body = [[error localizedDescription] dataUsingEncoding:NSUTF8StringEncoding];
        }
        return response;
        
    } else if ([method isEqualToString:@"OPTIONS"]) {
        // WebDAV OPTIONS
        response.statusCode = 200;
        response.contentType = @"text/plain";
        NSString *davMethods = @"1, 2";
        response.body = [davMethods dataUsingEncoding:NSUTF8StringEncoding];
        return response;
        
    } else {
        response.statusCode = 405;
        response.contentType = @"text/plain";
        response.body = [@"Method Not Allowed" dataUsingEncoding:NSUTF8StringEncoding];
        return response;
    }
}

// POST /api/webdav/start
- (TVNCHttpResponse *)handleWebDAVStart:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    // 固定根目录为 /，忽略客户端传的 root 参数
    self.webdavRootPath = @"/";

    self.webdavEnabled = YES;
    TVNCWriteBool(CFSTR("WebDAVEnabled"), YES);

    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"success": @YES,
        @"message": @"WebDAV 已启用",
        @"rootPath": @"/"
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// POST /api/webdav/stop
- (TVNCHttpResponse *)handleWebDAVStop {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    self.webdavEnabled = NO;
    TVNCWriteBool(CFSTR("WebDAVEnabled"), NO);
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"success": @YES,
        @"message": @"WebDAV 已停用"
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// GET /api/webdav/status
- (TVNCHttpResponse *)handleWebDAVStatus {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    BOOL enabled = TVNCReadBool(CFSTR("WebDAVEnabled"));
    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"enabled": @(enabled),
        @"rootPath": self.webdavRootPath ?: @"/"
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// GET /webdav or /webdav/ - 返回 WebDAV 浏览器界面
- (TVNCHttpResponse *)handleWebDAVUI {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    // 优先从文件系统读取 webdav.html（方便修改/调试）
    NSString *fsPath = @"/var/mobile/Library/MatisuXCS/webdav.html";
    if ([[NSFileManager defaultManager] fileExistsAtPath:fsPath]) {
        NSError *readError = nil;
        NSString *htmlString = [NSString stringWithContentsOfFile:fsPath encoding:NSUTF8StringEncoding error:&readError];
        if (htmlString && !readError) {
            response.statusCode = 200;
            response.contentType = @"text/html; charset=utf-8";
            response.body = [htmlString dataUsingEncoding:NSUTF8StringEncoding];
            return response;
        }
    }

    // Fallback: 使用内嵌的 base64 HTML
    NSData *htmlData = [[NSData alloc] initWithBase64EncodedString:kWebDAVHTMLBase64 options:0];
    if (htmlData) {
        response.statusCode = 200;
        response.contentType = @"text/html; charset=utf-8";
        response.body = htmlData;
    } else {
        // base64 解码失败，返回简单提示
        NSString *msg = @"<html><body><h2>WebDAV UI Error</h2><p>Failed to decode embedded HTML.</p></body></html>";
        response.statusCode = 200;
        response.contentType = @"text/html; charset=utf-8";
        response.body = [msg dataUsingEncoding:NSUTF8StringEncoding];
    }
    return response;
}

#pragma mark - API Handlers

// GET /api/screenshot?format=png&quality=0.8&rotation=90&scale=0.5
- (TVNCHttpResponse *)handleScreenshot:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    NSString *format = query[@"format"] ?: @"png";
    NSData *imageData = nil;
    
    // 解析旋转参数，默认0度
    NSInteger rotation = 0;
    NSString *rotationStr = query[@"rotation"];
    if (rotationStr) {
        rotation = [rotationStr integerValue];
        // 规范化到 0, 90, 180, 270
        rotation = ((rotation % 360) + 360) % 360;
        rotation = (rotation / 90) * 90;
    }
    
    // 解析质量参数，默认0.9
    CGFloat quality = 0.9;
    NSString *qualityStr = query[@"quality"];
    if (qualityStr) {
        quality = [qualityStr floatValue];
        if (quality < 0.0) quality = 0.0;
        if (quality > 1.0) quality = 1.0;
    }
    
    // 解析缩放参数，默认1.0（不缩放）
    CGFloat scale = 1.0;
    NSString *scaleStr = query[@"scale"];
    if (scaleStr) {
        scale = [scaleStr floatValue];
        if (scale < 0.1) scale = 0.1;
        if (scale > 1.0) scale = 1.0;
    }
    
    // 如果有缩放参数，使用带缩放+旋转的方法
    if (scale < 1.0 || rotation != 0) {
        imageData = [[TVNCApiManager sharedManager] captureScreenshotWithFormat:format quality:quality rotation:rotation scale:scale];
    } else {
        // 无旋转无缩放时使用原始方法
        if ([format isEqualToString:@"jpeg"] || [format isEqualToString:@"jpg"]) {
            imageData = [[TVNCApiManager sharedManager] captureScreenshotAsJPEGWithQuality:quality];
        } else {
            imageData = [[TVNCApiManager sharedManager] captureScreenshotAsPNG];
        }
    }
    
    if (imageData) {
        response.statusCode = 200;
        response.contentType = [format isEqualToString:@"png"] ? @"image/png" : @"image/jpeg";
        response.body = imageData;
    } else {
        response.statusCode = 500;
        response.contentType = @"application/json";
        NSDictionary *error = @{@"error": @"Screenshot failed"};
        response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
    }
    
    return response;
}

// GET /api/screenshot/fast?fmt=jpeg&q=0.6&scale=0.5&maxw=800&maxh=600
// 从 VNC 帧缓存快速截图，VNC 未运行时降级到 /api/screenshot
- (TVNCHttpResponse *)handleScreenshotFast:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    // 检查 VNC 帧缓存是否可用
    if ([[TVNCApiManager sharedManager] isFramebufferAvailable]) {
        // 解析参数
        NSString *format = query[@"fmt"] ?: query[@"format"] ?: @"jpeg";
        CGFloat quality = 0.6;
        NSString *qStr = query[@"q"] ?: query[@"quality"];
        if (qStr) {
            quality = [qStr floatValue];
            if (quality < 0.0) quality = 0.0;
            if (quality > 1.0) quality = 1.0;
        }
        CGFloat scale = 1.0;
        NSString *scaleStr = query[@"scale"];
        if (scaleStr) {
            scale = [scaleStr floatValue];
            if (scale < 0.1) scale = 0.1;
            if (scale > 1.0) scale = 1.0;
        }
        int maxW = 0, maxH = 0;
        if (query[@"maxw"]) maxW = [query[@"maxw"] intValue];
        if (query[@"maxh"]) maxH = [query[@"maxh"] intValue];

        NSData *imageData = [[TVNCApiManager sharedManager]
            captureScreenshotFromFramebufferWithFormat:format
                                               quality:quality
                                                 scale:scale
                                                  maxW:maxW
                                                  maxH:maxH];

        if (imageData) {
            response.statusCode = 200;
            response.contentType = ([format.lowercaseString containsString:@"png"]) ? @"image/png" : @"image/jpeg";
            response.body = imageData;
            // 添加 X-Source 头标识来源
            return response;
        }
    }

    // 降级到普通截图
    NSString *format = query[@"fmt"] ?: query[@"format"] ?: @"jpeg";
    CGFloat quality = 0.6;
    NSString *qStr = query[@"q"] ?: query[@"quality"];
    if (qStr) {
        quality = [qStr floatValue];
        if (quality < 0.0) quality = 0.0;
        if (quality > 1.0) quality = 1.0;
    }
    CGFloat scale = 1.0;
    NSString *scaleStr = query[@"scale"];
    if (scaleStr) {
        scale = [scaleStr floatValue];
        if (scale < 0.1) scale = 0.1;
        if (scale > 1.0) scale = 1.0;
    }

    NSData *imageData = nil;
    if (scale < 1.0) {
        imageData = [[TVNCApiManager sharedManager] captureScreenshotWithFormat:format quality:quality rotation:0 scale:scale];
    } else {
        if ([format.lowercaseString containsString:@"png"]) {
            imageData = [[TVNCApiManager sharedManager] captureScreenshotAsPNG];
        } else {
            imageData = [[TVNCApiManager sharedManager] captureScreenshotAsJPEGWithQuality:quality];
        }
    }

    if (imageData) {
        response.statusCode = 200;
        response.contentType = [format.lowercaseString containsString:@"png"] ? @"image/png" : @"image/jpeg";
        response.body = imageData;
    } else {
        response.statusCode = 500;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Screenshot failed"} options:0 error:nil];
    }

    return response;
}

// GET /api/stream.mjpeg?q=0.6&scale=0.5&fps=10&maxw=800&maxh=600
// MJPEG 持续推流（返回特殊响应，由 TVNCHttpConnection.handle 处理持续推帧）
- (TVNCHttpResponse *)handleStreamMjpeg:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    response.statusCode = 200;
    response.contentType = @"multipart/x-mixed-replace; boundary=frameboundary";

    // 将 MJPEG 参数编码到 body 中（JSON 格式，由 handle 方法解析）
    NSMutableDictionary *mjpegParams = [NSMutableDictionary dictionary];
    mjpegParams[@"q"] = @(0.6);
    if (query[@"q"] ?: query[@"quality"]) {
        CGFloat q = [(query[@"q"] ?: query[@"quality"]) floatValue];
        mjpegParams[@"q"] = @(q);
    }
    mjpegParams[@"scale"] = @(1.0);
    if (query[@"scale"]) {
        mjpegParams[@"scale"] = @([query[@"scale"] floatValue]);
    }
    mjpegParams[@"fps"] = @(10);
    if (query[@"fps"]) {
        int fps = [query[@"fps"] intValue];
        if (fps < 1) fps = 1;
        if (fps > 30) fps = 30;
        mjpegParams[@"fps"] = @(fps);
    }
    mjpegParams[@"maxw"] = @(0);
    if (query[@"maxw"]) mjpegParams[@"maxw"] = @([query[@"maxw"] intValue]);
    mjpegParams[@"maxh"] = @(0);
    if (query[@"maxh"]) mjpegParams[@"maxh"] = @([query[@"maxh"] intValue]);

    // 使用特殊标记 "__MJPEG_STREAM__" 让 handle 方法识别
    NSData *jsonData = [NSJSONSerialization dataWithJSONObject:mjpegParams options:0 error:nil];
    NSMutableData *markerData = [NSMutableData dataWithData:[@"__MJPEG_STREAM__" dataUsingEncoding:NSUTF8StringEncoding]];
    [markerData appendData:jsonData];
    response.body = markerData;

    return response;
}

// POST /api/writefile_text?path=/xxx&append=true
// Body: plain text (UTF-8)
- (TVNCHttpResponse *)handleWriteFileText:(NSDictionary *)query body:(NSData *)body {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    NSString *filePath = query[@"path"];
    if (!filePath || filePath.length == 0) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        NSDictionary *error = @{@"error": @"Missing path parameter"};
        response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
        return response;
    }
    
    BOOL append = [query[@"append"] isEqualToString:@"true"];
    
    TVLog(@"HTTP Server: WriteFileText request - path: %@, append: %@, size: %lu bytes", 
          filePath, append ? @"YES" : @"NO", (unsigned long)body.length);
    
    // 直接使用 body 作为文本内容
    NSError *error = nil;
    BOOL success = [[TVNCApiManager sharedManager] writeContent:body
                                                      toFilePath:filePath
                                                          append:append
                                                           error:&error];
    
    if (success) {
        response.statusCode = 200;
        response.contentType = @"application/json";
        NSDictionary *result = @{@"success": @YES, @"path": filePath, @"bytes": @(body.length)};
        response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    } else {
        response.statusCode = 500;
        response.contentType = @"application/json";
        NSString *errMsg = error ? error.localizedDescription : @"Unknown error";
        TVLog(@"HTTP Server: WriteFileText failed - %@", errMsg);
        NSDictionary *result = @{
            @"success": @NO, 
            @"error": errMsg,
            @"path": filePath
        };
        response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    }
    
    return response;
}

// POST /api/clipboard
// Body: base64 encoded text
- (TVNCHttpResponse *)handleClipboard:(NSDictionary *)query body:(NSData *)body {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    // 解析 body（base64）
    NSString *base64Content = [[NSString alloc] initWithData:body encoding:NSUTF8StringEncoding];
    base64Content = [base64Content stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    
    NSData *decodedData = [[NSData alloc] initWithBase64EncodedString:base64Content options:0];
    if (!decodedData) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        NSDictionary *error = @{@"error": @"Invalid base64 content"};
        response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
        return response;
    }
    
    NSString *text = [[NSString alloc] initWithData:decodedData encoding:NSUTF8StringEncoding];
    if (!text) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        NSDictionary *error = @{@"error": @"Invalid UTF-8 text"};
        response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
        return response;
    }
    
    BOOL success = [[TVNCApiManager sharedManager] setClipboardText:text];
    
    response.statusCode = success ? 200 : 500;
    response.contentType = @"application/json";
    NSDictionary *result = @{@"success": @(success), @"text": text};
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    
    return response;
}

// POST /api/clipboard_text
// Body: plain text (UTF-8)
- (TVNCHttpResponse *)handleClipboardText:(NSDictionary *)query body:(NSData *)body {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    // 直接解析 body 为 UTF-8 文本
    NSString *text = [[NSString alloc] initWithData:body encoding:NSUTF8StringEncoding];
    if (!text) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        NSDictionary *error = @{@"error": @"Invalid UTF-8 text"};
        response.body = [NSJSONSerialization dataWithJSONObject:error options:0 error:nil];
        return response;
    }
    
    BOOL success = [[TVNCApiManager sharedManager] setClipboardText:text];
    
    response.statusCode = success ? 200 : 500;
    response.contentType = @"application/json";
    NSDictionary *result = @{@"success": @(success), @"text": text};
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    
    return response;
}

// GET /api/clipboard - 获取剪贴板内容
- (TVNCHttpResponse *)handleClipboardGet:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    NSString *text = [[TVNCApiManager sharedManager] getClipboardText];
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{@"success": @YES, @"text": text ?: @""};
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    
    return response;
}

// GET /api/clipboard_text - 获取剪贴板内容（纯文本）
- (TVNCHttpResponse *)handleClipboardTextGet:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    NSString *text = [[TVNCApiManager sharedManager] getClipboardText];
    
    response.statusCode = 200;
    response.contentType = @"text/plain; charset=utf-8";
    response.body = (text ? [text dataUsingEncoding:NSUTF8StringEncoding] : [NSData data]);
    
    return response;
}

// GET /api/clients
- (TVNCHttpResponse *)handleClients {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    // 这里需要访问 trollvncserver 中的客户端列表
    // 暂时返回空列表，后续可以添加全局访问接口
    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{@"clients": @[], @"count": @0};
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    
    return response;
}

// GET /api/status
- (TVNCHttpResponse *)handleStatus {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    
    // 使用局部变量避免多线程竞争
    NSUInteger currentPort = self.port;
    
    // 运行时从 bundle 读取版本号，避免编译缓存导致版本号不匹配
    NSString *version = [NSBundle mainBundle].infoDictionary[@"CFBundleShortVersionString"];
    if (!version) {
        version = @PACKAGE_VERSION;
    }
    
    NSDictionary *result = @{
        @"status": @"running",
        @"httpPort": @(currentPort),
        @"version": version
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    
    return response;
}

// v3.43: 获取真实设备名（增强版）
// iOS 16+ daemon 上下文中 UIDevice name 返回泛化的 "iPhone"（隐私保护），
// 依次尝试: UIDevice name → MGCopyAnswer → MobileGestalt cache plist → preferences.plist → sysctl hostname → "iPhone"
static NSString *tvncGetRealDeviceName(void) {
    NSString *uidName = [[UIDevice currentDevice] name];

    // 1. 如果 UIDevice 返回的不是泛化的 "iPhone"，直接用
    if (uidName && uidName.length > 0 && ![uidName isEqualToString:@"iPhone"]) {
        return uidName;
    }

    // 2. 尝试 MGCopyAnswer("DeviceName") 私有 API
    //    v3.43: 已在 entitlements 中添加 com.apple.private.MobileGestalt.AllowedProtectedStrings
    void *mg = dlopen("/usr/lib/libMobileGestalt.dylib", RTLD_LAZY);
    if (mg) {
        CFStringRef (*MGCopyAnswerPtr)(CFStringRef) = (CFStringRef (*)(CFStringRef))dlsym(mg, "MGCopyAnswer");
        if (MGCopyAnswerPtr) {
            CFStringRef mgName = MGCopyAnswerPtr(CFSTR("DeviceName"));
            if (mgName) {
                NSString *result = [(__bridge_transfer NSString *)mgName
                    stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
                if (result.length > 0 && ![result isEqualToString:@"iPhone"]) {
                    return result;
                }
            }
        }
    }

    // 3. v3.43: 读 MobileGestalt cache plist（纯文件读取，不需要 entitlement）
    //    路径: /var/containers/Shared/SystemGroup/systemgroup.com.apple.mobilegestaltcache/Library/Caches/com.apple.MobileGestalt.plist
    NSMutableArray *mgCachePaths = [NSMutableArray array];
    if (access("/var/jb", F_OK) == 0) {
        [mgCachePaths addObject:@"/var/jb/var/containers/Shared/SystemGroup/systemgroup.com.apple.mobilegestaltcache/Library/Caches/com.apple.MobileGestalt.plist"];
    }
    [mgCachePaths addObject:@"/var/containers/Shared/SystemGroup/systemgroup.com.apple.mobilegestaltcache/Library/Caches/com.apple.MobileGestalt.plist"];
    for (NSString *mgPath in mgCachePaths) {
        NSDictionary *mgCache = [NSDictionary dictionaryWithContentsOfFile:mgPath];
        NSDictionary *cacheExtra = mgCache[@"CacheExtra"];
        NSString *devName = cacheExtra[@"DeviceName"];
        if ([devName isKindOfClass:[NSString class]] && devName.length > 0 && ![devName isEqualToString:@"iPhone"]) {
            return devName;
        }
    }

    // 4. 读 SystemConfiguration preferences.plist 中的 DeviceName
    NSMutableArray *plistPaths = [NSMutableArray array];
    if (access("/var/jb", F_OK) == 0) {
        [plistPaths addObject:@"/var/jb/var/mobile/Library/Preferences/SystemConfiguration/preferences.plist"];
        [plistPaths addObject:@"/var/jb/var/preferences/SystemConfiguration/preferences.plist"];
    }
    [plistPaths addObject:@"/var/mobile/Library/Preferences/SystemConfiguration/preferences.plist"];
    [plistPaths addObject:@"/var/preferences/SystemConfiguration/preferences.plist"];

    for (NSString *plistPath in plistPaths) {
        NSDictionary *prefs = [NSDictionary dictionaryWithContentsOfFile:plistPath];
        NSDictionary *controller = prefs[@"Controller"];
        NSString *devName = controller[@"DeviceName"];
        if (devName && devName.length > 0 && ![devName isEqualToString:@"iPhone"]) {
            return devName;
        }
    }

    // 5. v3.43: sysctl kern.hostname（iOS 上 hostname 通常由设备名派生）
    char hostname[256] = {0};
    size_t hsize = sizeof(hostname);
    if (sysctlbyname("kern.hostname", hostname, &hsize, NULL, 0) == 0) {
        NSString *hn = [[NSString stringWithUTF8String:hostname]
            stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
        if (hn.length > 0 && ![hn isEqualToString:@"iPhone"] && ![hn isEqualToString:@"localhost"]) {
            return hn;
        }
    }

    // 6. 尝试 hostname（NSProcessInfo）
    if (uidName && uidName.length > 0) {
        return uidName;
    }
    NSString *procHostname = [[NSProcessInfo processInfo] hostName];
    if (procHostname && procHostname.length > 0) {
        return procHostname;
    }

    return @"iPhone";
}

// GET /api/device
// 返回设备信息：设备名、设备ID、系统版本、电量、充电状态
// 支持参数：ip=客户端IP，save=true（保存到 /var/mobile/Media/fuwuduan.txt）
// 设备ID优先读取 /var/mobile/Media/.matisu_device_id，不存在则生成并保存
- (TVNCHttpResponse *)handleDeviceInfo:(NSDictionary *)query clientAddr:(NSString *)clientAddr {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    // 获取设备名称 (v3.41: 使用 tvncGetRealDeviceName 修复 iOS 16+ daemon 上下文返回 "iPhone" 的问题)
    NSString *deviceName = tvncGetRealDeviceName();
    
    // 获取系统版本
    NSString *systemVersion = [[UIDevice currentDevice] systemVersion];
    
    // 获取设备型号标识符 (如 iPhone15,2)
    NSString *deviceModel = nil;
    struct utsname systemInfo;
    uname(&systemInfo);
    deviceModel = [NSString stringWithCString:systemInfo.machine encoding:NSUTF8StringEncoding];
    
    // 获取设备UUID (作为设备ID)
    // 优先读取 .matisu_device_id 文件，如果没有则生成并保存
    NSString *deviceIDFile = @"/var/mobile/Media/.matisu_device_id";
    NSString *deviceUUID = nil;
    
    // 使用 NSData 读取文件（更兼容的方法）
    NSError *readError = nil;
    NSData *fileData = [NSData dataWithContentsOfFile:deviceIDFile options:0 error:&readError];
    NSString *savedDeviceId = nil;
    
    if (fileData && readError == nil) {
        savedDeviceId = [[NSString alloc] initWithData:fileData encoding:NSUTF8StringEncoding];
    }
    
    if (savedDeviceId && savedDeviceId.length > 0) {
        // 文件存在，读取已有的设备ID
        deviceUUID = [savedDeviceId stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
        TVLog(@"HTTP Server: Read existing deviceId from %@: %@", deviceIDFile, deviceUUID);
    } else {
        // 文件不存在，读取手机设备ID并保存
        deviceUUID = [[UIDevice currentDevice] identifierForVendor].UUIDString;
        
        NSError *writeError = nil;
        if ([deviceUUID writeToFile:deviceIDFile atomically:YES encoding:NSUTF8StringEncoding error:&writeError]) {
            TVLog(@"HTTP Server: Saved new deviceId to %@: %@", deviceIDFile, deviceUUID);
        } else {
            TVLog(@"HTTP Server: Failed to save deviceId to %@: %@", deviceIDFile, writeError);
        }
    }
    
    // 获取更友好的设备型号名称
    NSString *deviceModelName = [self deviceModelNameFromIdentifier:deviceModel];
    
    // 获取电量信息
    [[UIDevice currentDevice] setBatteryMonitoringEnabled:YES];
    float batteryLevel = [[UIDevice currentDevice] batteryLevel];
    UIDeviceBatteryState batteryState = [[UIDevice currentDevice] batteryState];
    [[UIDevice currentDevice] setBatteryMonitoringEnabled:NO];
    
    // 转换电量状态为字符串
    NSString *batteryStateString = @"unknown";
    switch (batteryState) {
        case UIDeviceBatteryStateUnplugged:
            batteryStateString = @"unplugged";  // 未充电
            break;
        case UIDeviceBatteryStateCharging:
            batteryStateString = @"charging";   // 正在充电
            break;
        case UIDeviceBatteryStateFull:
            batteryStateString = @"full";       // 已充满
            break;
        default:
            batteryStateString = @"unknown";
            break;
    }
    
    // 电量为 -1 表示无法获取
    NSNumber *batteryLevelNumber = (batteryLevel >= 0) ? @(batteryLevel * 100) : @(-1);
    
    // 获取存储空间信息
    NSError *storageError = nil;
    NSDictionary *storageAttrs = [[NSFileManager defaultManager] attributesOfFileSystemForPath:NSHomeDirectory() error:&storageError];
    
    NSMutableDictionary *storage = [NSMutableDictionary dictionary];
    if (storageAttrs) {
        unsigned long long totalSpace = [storageAttrs[NSFileSystemSize] unsignedLongLongValue];
        unsigned long long freeSpace = [storageAttrs[NSFileSystemFreeSize] unsignedLongLongValue];
        unsigned long long usedSpace = totalSpace - freeSpace;
        
        storage[@"totalBytes"] = @(totalSpace);
        storage[@"freeBytes"] = @(freeSpace);
        storage[@"usedBytes"] = @(usedSpace);
        storage[@"totalGB"] = [NSString stringWithFormat:@"%.1f", totalSpace / (1024.0 * 1024.0 * 1024.0)];
        storage[@"freeGB"] = [NSString stringWithFormat:@"%.1f", freeSpace / (1024.0 * 1024.0 * 1024.0)];
        storage[@"usedGB"] = [NSString stringWithFormat:@"%.1f", usedSpace / (1024.0 * 1024.0 * 1024.0)];
        storage[@"usagePercent"] = @(totalSpace > 0 ? (usedSpace * 100.0 / totalSpace) : 0);
    } else {
        storage[@"error"] = storageError.localizedDescription ?: @"Unable to get storage info";
    }
    
    // 构建设备信息字典
    NSMutableDictionary *result = [NSMutableDictionary dictionary];
    result[@"deviceName"] = deviceName ?: @"Unknown";
    result[@"deviceId"] = deviceUUID ?: @"Unknown";
    result[@"deviceModel"] = deviceModel ?: @"Unknown";
    result[@"deviceModelName"] = deviceModelName ?: @"Unknown";
    result[@"systemVersion"] = systemVersion ?: @"Unknown";
    result[@"systemName"] = [[UIDevice currentDevice] systemName] ?: @"iOS";
    result[@"batteryLevel"] = batteryLevelNumber;
    result[@"batteryState"] = batteryStateString;
    result[@"storage"] = storage;
    
    // 处理 save 参数
    NSString *saveParam = query[@"save"];
    BOOL shouldSave = [saveParam isEqualToString:@"true"] || [saveParam isEqualToString:@"1"];
    
    if (shouldSave) {
        // 获取 IP 参数（API 传入的 ip 作为 serverIP）
        NSString *serverIP = query[@"ip"];
        
        // 获取当前时间
        NSDateFormatter *formatter = [[NSDateFormatter alloc] init];
        [formatter setTimeZone:[NSTimeZone timeZoneWithName:@"UTC"]];
        [formatter setDateFormat:@"yyyy-MM-dd HH:mm:ss Z"];
        NSString *recordTime = [formatter stringFromDate:[NSDate date]];
        
        // 添加 serverIP 和 recordTime
        result[@"serverIP"] = serverIP ?: @"Unknown";
        result[@"recordTime"] = recordTime;
        
        // 保存到 /var/mobile/Media/fuwuduan.txt
        NSString *savePath = @"/var/mobile/Media/fuwuduan.txt";
        NSError *error = nil;
        NSData *jsonData = [NSJSONSerialization dataWithJSONObject:result options:NSJSONWritingPrettyPrinted error:&error];
        
        if (jsonData) {
            BOOL success = [jsonData writeToFile:savePath options:NSDataWritingAtomic error:&error];
            if (success) {
                TVLog(@"HTTP Server: Device info saved to %@", savePath);
                result[@"_saved"] = @YES;
                result[@"_savePath"] = savePath;
            } else {
                TVLog(@"HTTP Server: Failed to save device info: %@", error);
                result[@"_saved"] = @NO;
                result[@"_saveError"] = error.localizedDescription ?: @"Unknown error";
            }
        }
    }
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    response.body = [NSJSONSerialization dataWithJSONObject:result options:NSJSONWritingPrettyPrinted error:nil];
    
    return response;
}

