#pragma mark - 群控 WebSocket 服务器

// htonll / ntohll 辅助函数（iOS 不提供标准实现）
static inline uint64_t ws_htonll(uint64_t val) {
#if __BYTE_ORDER__ == __ORDER_LITTLE_ENDIAN__
    return ((uint64_t)htonl(val & 0xFFFFFFFF) << 32) | htonl(val >> 32);
#else
    return val;
#endif
}

static inline uint64_t ws_ntohll(uint64_t val) {
    return ws_htonll(val); // 同 htonll
}

// WebSocket 握手：计算 Sec-WebSocket-Accept
static NSString *wsCalculateAccept(NSString *key) {
    NSString *combined = [key stringByAppendingString:@"258EAFA5-E914-47DA-95CA-C5AB0DC85B11"];
    NSData *data = [combined dataUsingEncoding:NSUTF8StringEncoding];
    
    // SHA-1
    unsigned char digest[CC_SHA1_DIGEST_LENGTH];
    CC_SHA1(data.bytes, (CC_LONG)data.length, digest);
    
    // Base64
    NSData *hashData = [NSData dataWithBytes:digest length:CC_SHA1_DIGEST_LENGTH];
    NSString *base64 = [hashData base64EncodedStringWithOptions:0];
    return base64;
}

// 发送 WebSocket 文本帧
static void wsSendTextFrame(int sock, NSString *text) {
    if (sock < 0 || !text) return;
    
    NSData *payload = [text dataUsingEncoding:NSUTF8StringEncoding];
    NSUInteger len = payload.length;
    
    NSMutableData *frame = [NSMutableData data];
    uint8_t header[2];
    header[0] = 0x81; // FIN=1, opcode=0x1 (text)
    
    if (len <= 125) {
        header[1] = (uint8_t)len;
        [frame appendBytes:header length:2];
    } else if (len <= 65535) {
        header[1] = 126;
        [frame appendBytes:header length:2];
        uint16_t nlen = htons((uint16_t)len);
        [frame appendBytes:&nlen length:2];
    } else {
        header[1] = 127;
        [frame appendBytes:header length:2];
        uint64_t nlen = ws_htonll(len);
        [frame appendBytes:&nlen length:8];
    }
    
    [frame appendData:payload];
    send(sock, frame.bytes, frame.length, 0);
}

// 读取 WebSocket 帧（阻塞），返回 payload 字符串，出错返回 nil
static NSString *wsReadFrame(int sock) {
    uint8_t header[2];
    ssize_t n = recv(sock, header, 2, 0);
    if (n <= 0) return nil;
    
    // BOOL fin = (header[0] & 0x80) != 0;
    uint8_t opcode = header[0] & 0x0F;
    BOOL masked = (header[1] & 0x80) != 0;
    uint64_t payloadLen = header[1] & 0x7F;
    
    if (payloadLen == 126) {
        uint16_t extLen;
        if (recv(sock, &extLen, 2, 0) <= 0) return nil;
        payloadLen = ntohs(extLen);
    } else if (payloadLen == 127) {
        uint64_t extLen;
        if (recv(sock, &extLen, 8, 0) <= 0) return nil;
        payloadLen = ws_ntohll(extLen);
    }
    
    // 读取 masking key
    uint8_t mask[4] = {0};
    if (masked) {
        if (recv(sock, mask, 4, 0) <= 0) return nil;
    }
    
    // 读取 payload
    if (payloadLen > 1024 * 1024) return nil; // 1MB 限制
    NSMutableData *payload = [NSMutableData dataWithLength:(NSUInteger)payloadLen];
    NSUInteger received = 0;
    while (received < payloadLen) {
        ssize_t r = recv(sock, (uint8_t *)payload.mutableBytes + received, payloadLen - received, 0);
        if (r <= 0) return nil;
        received += r;
    }
    
    // Unmask
    if (masked) {
        uint8_t *bytes = (uint8_t *)payload.mutableBytes;
        for (NSUInteger i = 0; i < payloadLen; i++) {
            bytes[i] ^= mask[i % 4];
        }
    }
    
    // 处理 close 帧
    if (opcode == 0x08) {
        return @"__WS_CLOSE__";
    }
    
    // 处理 ping 帧
    if (opcode == 0x09) {
        // 自动回复 pong
        uint8_t pong[2] = {0x8A, 0x00};
        send(sock, pong, 2, 0);
        return @"__WS_PING__";
    }
    
    // 只处理 text 帧
    if (opcode != 0x01) return nil;
    
    return [[NSString alloc] initWithData:payload encoding:NSUTF8StringEncoding];
}

- (BOOL)startGroupWebSocketServer {
    if (_wsRunning) {
        return YES;
    }
    
    _wsServerSocket = socket(AF_INET, SOCK_STREAM, 0);
    if (_wsServerSocket < 0) {
        TVLog(@"Group WS: Failed to create socket");
        return NO;
    }
    
    int opt = 1;
    setsockopt(_wsServerSocket, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
    
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons((uint16_t)_groupWSPort);
    
    if (bind(_wsServerSocket, (struct sockaddr *)&addr, sizeof(addr)) < 0) {
        TVLog(@"Group WS: Failed to bind to port %lu", (unsigned long)_groupWSPort);
        close(_wsServerSocket);
        _wsServerSocket = -1;
        return NO;
    }
    
    if (listen(_wsServerSocket, 10) < 0) {
        TVLog(@"Group WS: Failed to listen");
        close(_wsServerSocket);
        _wsServerSocket = -1;
        return NO;
    }
    
    _wsRunning = YES;
    TVLog(@"Group WS: Started on port %lu (master=%d)", (unsigned long)_groupWSPort, _groupMasterEnabled);
    
    dispatch_async(_wsServerQueue, ^{
        [self acceptWSConnections];
    });
    
    return YES;
}

- (void)stopGroupWebSocketServer {
    if (!_wsRunning && !_groupMasterEnabled) {
        return;
    }
    
    _wsRunning = NO;
    _groupMasterEnabled = NO;  // 重置主控标记，允许后续切换为从控
    
    // 关闭所有客户端连接
    @synchronized (_wsClientSockets) {
        for (NSNumber *sockNum in _wsClientSockets) {
            close(sockNum.intValue);
        }
        [_wsClientSockets removeAllObjects];
    }
    @synchronized (_wsClientIPs) {
        [_wsClientIPs removeAllObjects];
    }
    
    if (_wsServerSocket >= 0) {
        close(_wsServerSocket);
        _wsServerSocket = -1;
    }
    
    TVLog(@"Group WS: Stopped");
}

- (void)acceptWSConnections {
    while (_wsRunning) {
        struct sockaddr_in clientAddr;
        socklen_t addrLen = sizeof(clientAddr);
        
        int clientSocket = accept(_wsServerSocket, (struct sockaddr *)&clientAddr, &addrLen);
        if (clientSocket < 0) {
            if (_wsRunning) {
                TVLog(@"Group WS: Accept failed");
            }
            continue;
        }
        
        // 获取客户端 IP
        char ipStr[INET_ADDRSTRLEN];
        inet_ntop(AF_INET, &clientAddr.sin_addr, ipStr, INET_ADDRSTRLEN);
        NSString *clientIP = [NSString stringWithUTF8String:ipStr];
        TVLog(@"Group WS: New connection from %@", clientIP);
        
        // 在后台处理 WebSocket 握手
        dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
            [self handleWShandshake:clientSocket clientIP:clientIP];
        });
    }
}

- (void)handleWShandshake:(int)sock clientIP:(NSString *)ip {
    // 设置超时
    struct timeval tv;
    tv.tv_sec = 10;
    tv.tv_usec = 0;
    setsockopt(sock, SOL_SOCKET, SO_RCVTIMEO, &tv, sizeof(tv));
    
    // 读取 HTTP 升级请求
    NSMutableData *headerData = [NSMutableData data];
    uint8_t buffer[4096];
    while (headerData.length < 64 * 1024) {
        ssize_t n = recv(sock, buffer, sizeof(buffer), 0);
        if (n <= 0) break;
        [headerData appendBytes:buffer length:n];
        
        NSRange endRange = [headerData rangeOfData:[@"\r\n\r\n" dataUsingEncoding:NSUTF8StringEncoding]
                                            options:0
                                              range:NSMakeRange(0, headerData.length)];
        if (endRange.location != NSNotFound) break;
    }
    
    NSString *headerStr = [[NSString alloc] initWithData:headerData encoding:NSUTF8StringEncoding];
    if (!headerStr) {
        TVLog(@"Group WS: Invalid handshake from %@", ip);
        close(sock);
        return;
    }
    
    // 验证 WebSocket 升级请求
    NSArray *lines = [headerStr componentsSeparatedByString:@"\r\n"];
    if (lines.count == 0 || ![lines[0] hasPrefix:@"GET"]) {
        TVLog(@"Group WS: Not a WebSocket upgrade request from %@", ip);
        close(sock);
        return;
    }
    
    // 解析请求头
    NSString *wsKey = nil;
    for (NSString *line in lines) {
        if ([line hasPrefix:@"Sec-WebSocket-Key:"]) {
            wsKey = [[line substringFromIndex:18] stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceCharacterSet]];
        }
    }
    
    if (!wsKey) {
        TVLog(@"Group WS: Missing Sec-WebSocket-Key from %@", ip);
        close(sock);
        return;
    }
    
    // 计算握手响应
    NSString *acceptKey = wsCalculateAccept(wsKey);
    
    // 发送握手响应
    NSString *response = [NSString stringWithFormat:
        @"HTTP/1.1 101 Switching Protocols\r\n"
        @"Upgrade: websocket\r\n"
        @"Connection: Upgrade\r\n"
        @"Sec-WebSocket-Accept: %@\r\n"
        @"\r\n", acceptKey];
    
    send(sock, [response UTF8String], [response lengthOfBytesUsingEncoding:NSUTF8StringEncoding], 0);
    
    TVLog(@"Group WS: Handshake complete with %@", ip);
    
    // 添加到客户端列表
    @synchronized (_wsClientSockets) {
        [_wsClientSockets addObject:@(sock)];
    }
    @synchronized (_wsClientIPs) {
        [_wsClientIPs setObject:ip forKey:@(sock)];
    }

    // 设置长超时
    struct timeval longTv;
    longTv.tv_sec = 300;
    longTv.tv_usec = 0;
    setsockopt(sock, SOL_SOCKET, SO_RCVTIMEO, &longTv, sizeof(longTv));

    // 如果是主控模式，发欢迎消息，然后主控会通过 broadcastGroupEvent 主动推送
    if (_groupMasterEnabled) {
        wsSendTextFrame(sock, @"{\"type\":\"welcome\",\"role\":\"slave\",\"master\":true}");
        // 主控模式下，启动消息读取线程
        // 支持：1) 从控心跳检测 2) Web 客户端发送触摸事件（注入本地 + 广播其他从控）
        dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_DEFAULT, 0), ^{
            while (_wsRunning) {
                NSString *msg = wsReadFrame(sock);
                if (!msg || [msg isEqualToString:@"__WS_CLOSE__"]) {
                    break;
                }
                if ([msg isEqualToString:@"__WS_PING__"]) {
                    continue; // ping 已自动回复
                }
                // 解析 JSON 消息（Web 客户端发来的触摸/按键事件）
                NSData *jsonData = [msg dataUsingEncoding:NSUTF8StringEncoding];
                NSDictionary *event = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:nil];
                if (event) {
                    NSString *type = event[@"type"];
                    if ([type isEqualToString:@"touch"]) {
                        // 注入到主控本地
                        [self executeGroupTouchEvent:event];
                        // 广播给其他从控（排除发送者）
                        [self broadcastGroupEvent:msg exceptSock:sock];
                    } else if ([type isEqualToString:@"key"]) {
                        [self executeGroupKeyEvent:event];
                        [self broadcastGroupEvent:msg exceptSock:sock];
                    }
                }
            }
            // 客户端断开
            @synchronized (_wsClientSockets) {
                [_wsClientSockets removeObject:@(sock)];
            }
            @synchronized (_wsClientIPs) {
                [_wsClientIPs removeObjectForKey:@(sock)];
            }
            close(sock);
            TVLog(@"Group WS: Client disconnected");
        });
    } else {
        // 非主控模式但有 WS 连接（兼容：可能是 HTTP API 触发从控模式）
        // 不处理，直接关闭
        close(sock);
    }
}

// 从控模式：持续接收主控的 WebSocket 帧，执行触摸事件
- (void)handleWSClientFrames:(int)sock {
    while (_wsRunning) {
        NSString *msg = wsReadFrame(sock);
        if (!msg || [msg isEqualToString:@"__WS_CLOSE__"]) {
            break;
        }
        if ([msg isEqualToString:@"__WS_PING__"]) {
            continue; // ping 已自动回复
        }
        
        // 解析 JSON
        NSData *jsonData = [msg dataUsingEncoding:NSUTF8StringEncoding];
        NSDictionary *event = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:nil];
        if (!event) continue;
        
        NSString *type = event[@"type"];
        if ([type isEqualToString:@"touch"]) {
            // 从控收到触摸事件，注入到设备
            [self executeGroupTouchEvent:event];
        } else if ([type isEqualToString:@"key"]) {
            [self executeGroupKeyEvent:event];
        }
    }
    
    // 连接断开
    @synchronized (_wsClientSockets) {
        [_wsClientSockets removeObject:@(sock)];
    }
    close(sock);
    TVLog(@"Group WS: Client disconnected");
}

// 从控执行触摸事件
- (void)executeGroupTouchEvent:(NSDictionary *)event {
    double nx = [event[@"x"] doubleValue];
    double ny = [event[@"y"] doubleValue];
    NSString *action = event[@"action"];
    
    // 屏幕尺寸缓存：避免每次都读 UIScreen（主线程属性），只在方向变化时更新
    UIInterfaceOrientation curOrient = [UIApplication sharedApplication].statusBarOrientation;
    if (_cachedScreenWidth <= 0 || curOrient != _cachedOrientation) {
        CGFloat screenScale = [[UIScreen mainScreen] scale];
        _cachedScreenWidth = [UIScreen mainScreen].bounds.size.width * screenScale;
        _cachedScreenHeight = [UIScreen mainScreen].bounds.size.height * screenScale;
        _cachedOrientation = curOrient;
    }
    
    // 归一化坐标转设备坐标
    CGFloat dx = nx * _cachedScreenWidth;
    CGFloat dy = ny * _cachedScreenHeight;
    
    STHIDEventGenerator *gen = [STHIDEventGenerator sharedGenerator];
    CGPoint pt = CGPointMake(dx, dy);
    
    // 同步保护：防止 VNC ptrAddEvent 和群控同时操作 STHIDEventGenerator
    @synchronized (gen) {
        if ([action isEqualToString:@"down"]) {
            [gen touchDownAtPoints:&pt touchCount:1];
        } else if ([action isEqualToString:@"move"]) {
            [gen _updateTouchPoints:&pt count:1];
        } else if ([action isEqualToString:@"up"]) {
            [gen liftUpAtPoints:&pt touchCount:1];
        }
    }
}

// 从控执行按键事件
- (void)executeGroupKeyEvent:(NSDictionary *)event {
    NSString *action = event[@"action"];
    STHIDEventGenerator *gen = [STHIDEventGenerator sharedGenerator];
    
    if ([action isEqualToString:@"home_down"]) {
        [gen menuDown];
    } else if ([action isEqualToString:@"home_up"]) {
        [gen menuUp];
    } else if ([action isEqualToString:@"power_down"]) {
        [gen powerDown];
    } else if ([action isEqualToString:@"power_up"]) {
        [gen powerUp];
    }
}

- (void)broadcastGroupEvent:(NSString *)eventJSON {
    [self broadcastGroupEvent:eventJSON exceptSock:-1];
}

- (NSInteger)groupSlaveCount {
    @synchronized (_wsClientSockets) {
        return _wsClientSockets.count;
    }
}

- (NSArray<NSString *> *)groupSlaveIPs {
    @synchronized (_wsClientIPs) {
        return [_wsClientIPs allValues];
    }
}

- (void)broadcastGroupEvent:(NSString *)eventJSON exceptSock:(int)excludeSock {
    if (!_wsRunning || !_groupMasterEnabled) return;

    // 一次性构造 WS 帧，所有 socket 共享（避免每个 socket 重复构造 header+payload）
    NSData *payload = [eventJSON dataUsingEncoding:NSUTF8StringEncoding];
    NSUInteger len = payload.length;

    NSMutableData *frame = [NSMutableData data];
    uint8_t header[2];
    header[0] = 0x81; // FIN=1, opcode=0x1 (text)
    if (len <= 125) {
        header[1] = (uint8_t)len;
        [frame appendBytes:header length:2];
    } else if (len <= 65535) {
        header[1] = 126;
        [frame appendBytes:header length:2];
        uint16_t nlen = htons((uint16_t)len);
        [frame appendBytes:&nlen length:2];
    } else {
        header[1] = 127;
        [frame appendBytes:header length:2];
        uint64_t nlen = ws_htonll(len);
        [frame appendBytes:&nlen length:8];
    }
    [frame appendData:payload];

    @synchronized (_wsClientSockets) {
        NSMutableArray *broken = [NSMutableArray array];
        for (NSNumber *sockNum in _wsClientSockets) {
            int s = sockNum.intValue;
            if (s == excludeSock) continue; // 排除发送者

            ssize_t ret = send(s, frame.bytes, frame.length, 0);
            if (ret < 0) {
                [broken addObject:sockNum];
            }
        }
        // 清理断开的连接
        for (NSNumber *sockNum in broken) {
            close(sockNum.intValue);
            [_wsClientSockets removeObject:sockNum];
            @synchronized (_wsClientIPs) {
                [_wsClientIPs removeObjectForKey:sockNum];
            }
        }
    }
}

#pragma mark - 从控模式：连接到主控

- (BOOL)connectToMaster:(NSString *)masterIP port:(NSUInteger)port {
    if (_masterConnected) {
        [self disconnectFromMaster];
    }
    
    _masterSocket = socket(AF_INET, SOCK_STREAM, 0);
    if (_masterSocket < 0) {
        TVLog(@"Group Slave: Failed to create socket");
        return NO;
    }
    
    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((uint16_t)port);
    
    if (inet_pton(AF_INET, [masterIP UTF8String], &addr.sin_addr) <= 0) {
        TVLog(@"Group Slave: Invalid IP %@", masterIP);
        close(_masterSocket);
        _masterSocket = -1;
        return NO;
    }
    
    // 设置连接超时
    struct timeval tv;
    tv.tv_sec = 5;
    tv.tv_usec = 0;
    setsockopt(_masterSocket, SOL_SOCKET, SO_SNDTIMEO, &tv, sizeof(tv));
    
    if (connect(_masterSocket, (struct sockaddr *)&addr, sizeof(addr)) < 0) {
        TVLog(@"Group Slave: Failed to connect to %@:%lu", masterIP, (unsigned long)port);
        close(_masterSocket);
        _masterSocket = -1;
        return NO;
    }
    
    // 发送 WebSocket 握手请求
    NSString *wsKey = @"dGhlIHNhbXBsZSBub25jZQ=="; // 固定 key（简单实现）
    NSString *handshake = [NSString stringWithFormat:
        @"GET / HTTP/1.1\r\n"
        @"Host: %@:%lu\r\n"
        @"Upgrade: websocket\r\n"
        @"Connection: Upgrade\r\n"
        @"Sec-WebSocket-Key: %@\r\n"
        @"Sec-WebSocket-Version: 13\r\n"
        @"\r\n", masterIP, (unsigned long)port, wsKey];
    
    send(_masterSocket, [handshake UTF8String], [handshake lengthOfBytesUsingEncoding:NSUTF8StringEncoding], 0);
    
    // 读取握手响应
    NSMutableData *responseData = [NSMutableData data];
    uint8_t buffer[4096];
    struct timeval recvTv;
    recvTv.tv_sec = 5;
    recvTv.tv_usec = 0;
    setsockopt(_masterSocket, SOL_SOCKET, SO_RCVTIMEO, &recvTv, sizeof(recvTv));
    
    while (responseData.length < 64 * 1024) {
        ssize_t n = recv(_masterSocket, buffer, sizeof(buffer), 0);
        if (n <= 0) break;
        [responseData appendBytes:buffer length:n];
        
        NSRange endRange = [responseData rangeOfData:[@"\r\n\r\n" dataUsingEncoding:NSUTF8StringEncoding]
                                            options:0
                                              range:NSMakeRange(0, responseData.length)];
        if (endRange.location != NSNotFound) break;
    }
    
    NSString *responseStr = [[NSString alloc] initWithData:responseData encoding:NSUTF8StringEncoding];
    if (!responseStr || ![responseStr hasPrefix:@"HTTP/1.1 101"]) {
        TVLog(@"Group Slave: WebSocket handshake failed");
        close(_masterSocket);
        _masterSocket = -1;
        return NO;
    }
    
    _masterConnected = YES;
    _masterIP = masterIP;
    _masterPort = port;
    
    TVLog(@"Group Slave: Connected to master %@:%lu", masterIP, (unsigned long)port);
    
    // 启动接收线程
    dispatch_async(_masterQueue, ^{
        [self receiveMasterEvents];
    });
    
    return YES;
}

- (void)disconnectFromMaster {
    if (!_masterConnected) return;
    
    _masterConnected = NO;
    
    if (_masterSocket >= 0) {
        close(_masterSocket);
        _masterSocket = -1;
    }
    
    TVLog(@"Group Slave: Disconnected from master");
}

- (BOOL)isConnectedToMaster {
    return _masterConnected;
}

#pragma mark - 电脑中继模式 (Relay Mode)

- (BOOL)isRelayConnected {
    return _relayConnected;
}

- (BOOL)connectToRelay:(NSString *)relayIP port:(NSUInteger)port role:(NSString *)role {
    if (_relayConnected) {
        [self disconnectFromRelay];
    }

    _relaySocket = socket(AF_INET, SOCK_STREAM, 0);
    if (_relaySocket < 0) {
        TVLog(@"Relay: Failed to create socket");
        return NO;
    }

    struct sockaddr_in addr;
    memset(&addr, 0, sizeof(addr));
    addr.sin_family = AF_INET;
    addr.sin_port = htons((uint16_t)port);

    if (inet_pton(AF_INET, [relayIP UTF8String], &addr.sin_addr) <= 0) {
        TVLog(@"Relay: Invalid IP %@", relayIP);
        close(_relaySocket);
        _relaySocket = -1;
        return NO;
    }

    struct timeval tv;
    tv.tv_sec = 5;
    tv.tv_usec = 0;
    setsockopt(_relaySocket, SOL_SOCKET, SO_SNDTIMEO, &tv, sizeof(tv));

    if (connect(_relaySocket, (struct sockaddr *)&addr, sizeof(addr)) < 0) {
        TVLog(@"Relay: Failed to connect to %@:%lu", relayIP, (unsigned long)port);
        close(_relaySocket);
        _relaySocket = -1;
        return NO;
    }

    // WebSocket 握手（带 role 查询参数）
    NSString *wsKey = @"dGhlIHNhbXBsZSBub25jZQ==";
    NSString *pathWithRole = [NSString stringWithFormat:@"/?role=%@&deviceId=%@", role,
                              [UIDevice currentDevice].identifierForVendor.UUIDString ?: @"unknown"];
    NSString *handshake = [NSString stringWithFormat:
        @"GET %@ HTTP/1.1\r\n"
        @"Host: %@:%lu\r\n"
        @"Upgrade: websocket\r\n"
        @"Connection: Upgrade\r\n"
        @"Sec-WebSocket-Key: %@\r\n"
        @"Sec-WebSocket-Version: 13\r\n"
        @"\r\n", pathWithRole, relayIP, (unsigned long)port, wsKey];

    send(_relaySocket, [handshake UTF8String], [handshake lengthOfBytesUsingEncoding:NSUTF8StringEncoding], 0);

    // 读取握手响应
    NSMutableData *responseData = [NSMutableData data];
    uint8_t buffer[4096];
    struct timeval recvTv;
    recvTv.tv_sec = 5;
    recvTv.tv_usec = 0;
    setsockopt(_relaySocket, SOL_SOCKET, SO_RCVTIMEO, &recvTv, sizeof(recvTv));

    while (responseData.length < 64 * 1024) {
        ssize_t n = recv(_relaySocket, buffer, sizeof(buffer), 0);
        if (n <= 0) break;
        [responseData appendBytes:buffer length:n];

        NSRange endRange = [responseData rangeOfData:[@"\r\n\r\n" dataUsingEncoding:NSUTF8StringEncoding]
                                            options:0
                                              range:NSMakeRange(0, responseData.length)];
        if (endRange.location != NSNotFound) break;
    }

    NSString *responseStr = [[NSString alloc] initWithData:responseData encoding:NSUTF8StringEncoding];
    if (!responseStr || ![responseStr hasPrefix:@"HTTP/1.1 101"]) {
        TVLog(@"Relay: WebSocket handshake failed");
        close(_relaySocket);
        _relaySocket = -1;
        return NO;
    }

    _relayModeEnabled = YES;
    _relayConnected = YES;
    _relayIP = relayIP;
    _relayPort = port;
    _relayRole = role;

    TVLog(@"Relay: Connected to computer %@:%lu as %@", relayIP, (unsigned long)port, role);

    // 启动接收线程
    dispatch_async(_relayQueue, ^{
        [self receiveRelayEvents];
    });

    return YES;
}

- (void)disconnectFromRelay {
    if (!_relayConnected && !_relayModeEnabled) return;

    _relayConnected = NO;
    _relayModeEnabled = NO;

    if (_relaySocket >= 0) {
        close(_relaySocket);
        _relaySocket = -1;
    }
    _relayIP = nil;

    TVLog(@"Relay: Disconnected from computer relay server");
}

// 主控设备上报真实触摸事件到电脑中继服务器
// 在 ptrAddEvent 中被调用，仅主控角色需要调用此方法
- (void)reportRealTouchToRelay:(NSString *)action nx:(double)nx ny:(double)ny {
    if (!_relayConnected || ![_relayRole isEqualToString:@"master"]) return;

    NSDictionary *event = @{
        @"type": @"touch",
        @"action": action,
        @"x": @(nx),
        @"y": @(ny),
        @"source": @"real_touch"  // 标记来源：主控真实触摸
    };

    NSData *jsonData = [NSJSONSerialization dataWithJSONObject:event options:0 error:nil];
    if (!jsonData) return;

    NSString *jsonStr = [[NSString alloc] initWithData:jsonData encoding:NSUTF8StringEncoding];
    wsSendTextFrame(_relaySocket, jsonStr);
}

// 通过中继 WebSocket 发送文本消息（供 trollvncserver.mm 调用）
- (void)sendRelayMessage:(NSString *)text {
    if (!_relayConnected || _relaySocket < 0) return;
    wsSendTextFrame(_relaySocket, text);
}

// 从控模式：持续接收电脑中继服务器的 WebSocket 事件
- (void)receiveRelayEvents {
    struct timeval longTv;
    longTv.tv_sec = 300;
    longTv.tv_usec = 0;
    setsockopt(_relaySocket, SOL_SOCKET, SO_RCVTIMEO, &longTv, sizeof(longTv));

    while (_relayConnected) {
        NSString *msg = wsReadFrame(_relaySocket);
        if (!msg || [msg isEqualToString:@"__WS_CLOSE__"]) {
            TVLog(@"Relay: Computer closed connection");
            break;
        }
        if ([msg isEqualToString:@"__WS_PING__"]) continue;

        NSData *jsonData = [msg dataUsingEncoding:NSUTF8StringEncoding];
        NSDictionary *event = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:nil];
        if (!event) continue;

        NSString *type = event[@"type"];
        if ([type isEqualToString:@"touch"]) {
            self.isInjectingTouchEvent = YES;  // 防回环：标记为注入事件
            [self executeGroupTouchEvent:event];
            self.isInjectingTouchEvent = NO;
        } else if ([type isEqualToString:@"key"]) {
            self.isInjectingTouchEvent = YES;
            [self executeGroupKeyEvent:event];
            self.isInjectingTouchEvent = NO;
        }
    }

    _relayConnected = NO;
    if (_relaySocket >= 0) {
        close(_relaySocket);
        _relaySocket = -1;
    }
    TVLog(@"Relay: Receive loop ended");
}

// 从控模式：持续接收主控的 WebSocket 事件
- (void)receiveMasterEvents {
    // 设置长超时
    struct timeval longTv;
    longTv.tv_sec = 300;
    longTv.tv_usec = 0;
    setsockopt(_masterSocket, SOL_SOCKET, SO_RCVTIMEO, &longTv, sizeof(longTv));
    
    while (_masterConnected) {
        NSString *msg = wsReadFrame(_masterSocket);
        if (!msg || [msg isEqualToString:@"__WS_CLOSE__"]) {
            TVLog(@"Group Slave: Master closed connection");
            break;
        }
        if ([msg isEqualToString:@"__WS_PING__"]) {
            continue; // ping 已自动回复
        }
        
        // 解析 JSON
        NSData *jsonData = [msg dataUsingEncoding:NSUTF8StringEncoding];
        NSDictionary *event = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:nil];
        if (!event) continue;
        
        NSString *type = event[@"type"];
        if ([type isEqualToString:@"touch"]) {
            [self executeGroupTouchEvent:event];
        } else if ([type isEqualToString:@"key"]) {
            [self executeGroupKeyEvent:event];
        }
    }
    
    _masterConnected = NO;
    if (_masterSocket >= 0) {
        close(_masterSocket);
        _masterSocket = -1;
    }
    TVLog(@"Group Slave: Receive loop ended");
}

#pragma mark - 群控 API 处理方法

// POST /api/group/start?master=1&port=8183
- (TVNCHttpResponse *)handleGroupStart:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    NSString *masterStr = query[@"master"];
    self.groupMasterEnabled = (masterStr && [masterStr isEqualToString:@"1"]);
    
    NSString *portStr = query[@"port"];
    if (portStr) {
        self.groupWSPort = (NSUInteger)[portStr integerValue];
    }
    
    BOOL success = [self startGroupWebSocketServer];
    
    response.statusCode = success ? 200 : 500;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"success": @(success),
        @"master": @(self.groupMasterEnabled),
        @"port": @(self.groupWSPort),
        @"slaves": @(self.groupSlaveCount)
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// POST /api/group/stop
- (TVNCHttpResponse *)handleGroupStop {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    [self stopGroupWebSocketServer];
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{@"success": @YES};
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// GET /api/group/status
- (TVNCHttpResponse *)handleGroupStatus {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"running": @(_wsRunning),
        @"master": @(_groupMasterEnabled),
        @"port": @(_groupWSPort),
        @"slaves": @(self.groupSlaveCount),
        @"slaveConnected": @(_masterConnected),
        @"masterIP": _masterIP ?: @"",
        // 电脑中继模式
        @"relayMode": @(_relayModeEnabled),
        @"relayConnected": @(_relayConnected),
        @"relayIp": _relayIP ?: @"",
        @"relayPort": @(_relayPort),
        @"role": _relayRole ?: @""
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// POST /api/group/touch  （从控：HTTP API 方式接收触摸事件）
- (TVNCHttpResponse *)handleGroupTouch:(NSData *)body {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    if (!body) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Missing body"} options:0 error:nil];
        return response;
    }
    
    NSDictionary *event = [NSJSONSerialization JSONObjectWithData:body options:0 error:nil];
    if (!event) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Invalid JSON"} options:0 error:nil];
        return response;
    }
    
    NSString *type = event[@"type"];
    if ([type isEqualToString:@"touch"]) {
        [self executeGroupTouchEvent:event];
    } else if ([type isEqualToString:@"key"]) {
        [self executeGroupKeyEvent:event];
    }
    
    response.statusCode = 200;
    response.contentType = @"application/json";
    response.body = [NSJSONSerialization dataWithJSONObject:@{@"success": @YES} options:0 error:nil];
    return response;
}

// POST /api/group/connect?ip=192.168.x.x&port=8183  （从控连接到主控）
- (TVNCHttpResponse *)handleGroupConnect:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    
    NSString *ip = query[@"ip"];
    NSString *portStr = query[@"port"];
    NSUInteger port = portStr ? (NSUInteger)[portStr integerValue] : 8183;
    
    if (!ip) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Missing ip parameter"} options:0 error:nil];
        return response;
    }
    
    // 设备不能同时作为主控和从控
    if (_groupMasterEnabled) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Already running as master"} options:0 error:nil];
        return response;
    }
    
    BOOL success = [self connectToMaster:ip port:port];
    
    response.statusCode = success ? 200 : 500;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"success": @(success),
        @"masterIP": ip,
        @"port": @(port)
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// POST /api/group/disconnect  （从控断开与主控的连接）
- (TVNCHttpResponse *)handleGroupDisconnect {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    [self disconnectFromMaster];

    response.statusCode = 200;
    response.contentType = @"application/json";
    response.body = [NSJSONSerialization dataWithJSONObject:@{@"success": @YES} options:0 error:nil];
    return response;
}

#pragma mark - 电脑中继模式 API

// 从 /var/mobile/Media/fuwuduan.txt 读取电脑 IP
// 支持格式：
//   1. 键值对：serverIP=192.168.1.100
//   2. JSON：{"serverIP": "192.168.1.100"}
//   3. 纯 IP：192.168.1.100
- (NSString *)readServerIPFromConfigFile {
    NSString *configPath = @"/var/mobile/Media/fuwuduan.txt";
    NSFileManager *fm = [NSFileManager defaultManager];
    
    if (![fm fileExistsAtPath:configPath]) {
        TVLog(@"Relay: Config file not found: %@", configPath);
        return nil;
    }
    
    NSError *error = nil;
    NSString *content = [NSString stringWithContentsOfFile:configPath
                                                  encoding:NSUTF8StringEncoding
                                                     error:&error];
    if (!content || content.length == 0) {
        TVLog(@"Relay: Failed to read config file: %@", error.localizedDescription ?: @"empty");
        return nil;
    }
    
    // 去掉首尾空白和换行
    content = [content stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
    
    // 尝试 JSON 格式
    NSData *jsonData = [content dataUsingEncoding:NSUTF8StringEncoding];
    if (jsonData) {
        NSError *jsonError = nil;
        id jsonObject = [NSJSONSerialization JSONObjectWithData:jsonData options:0 error:&jsonError];
        if (jsonObject && [jsonObject isKindOfClass:[NSDictionary class]]) {
            NSString *ip = jsonObject[@"serverIP"];
            if (ip && ip.length > 0) {
                TVLog(@"Relay: Read serverIP from JSON: %@", ip);
                return ip;
            }
        }
    }
    
    // 尝试键值对格式（serverIP=192.168.1.100）
    NSArray *lines = [content componentsSeparatedByString:@"\n"];
    for (NSString *line in lines) {
        NSString *trimmedLine = [line stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
        if ([trimmedLine hasPrefix:@"serverIP="] || [trimmedLine hasPrefix:@"serverIP = "]) {
            NSString *ip = [trimmedLine componentsSeparatedByString:@"="].lastObject;
            ip = [ip stringByTrimmingCharactersInSet:[NSCharacterSet whitespaceAndNewlineCharacterSet]];
            if (ip && ip.length > 0) {
                TVLog(@"Relay: Read serverIP from key-value: %@", ip);
                return ip;
            }
        }
    }
    
    // 尝试纯 IP 格式（整行就是一个 IP 地址）
    // 简单验证：包含数字和点，且至少有 7 个字符（x.x.x.x 最少 7 个字符）
    NSCharacterSet *ipCharSet = [NSCharacterSet characterSetWithCharactersInString:@"0123456789."];
    NSString *filtered = [[content componentsSeparatedByCharactersInSet:[ipCharSet invertedSet]] componentsJoinedByString:@""];
    if (filtered.length >= 7 && [filtered containsString:@"."]) {
        TVLog(@"Relay: Read serverIP as plain IP: %@", filtered);
        return filtered;
    }
    
    TVLog(@"Relay: Cannot parse serverIP from config file");
    return nil;
}

// POST /api/group/relay/start?relayIp=192.168.x.x&relayPort=8183&role=master|slave
- (TVNCHttpResponse *)handleRelayStart:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    NSString *relayIP = query[@"relayIp"];
    NSString *portStr = query[@"relayPort"];
    NSString *role = query[@"role"] ?: @"slave";

    // 如果没有提供 relayIp 参数，尝试从配置文件读取
    if (!relayIP || relayIP.length == 0) {
        TVLog(@"Relay: relayIp not provided, reading from config file...");
        relayIP = [self readServerIPFromConfigFile];
        if (!relayIP || relayIP.length == 0) {
            response.statusCode = 400;
            response.contentType = @"application/json";
            response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Missing relayIp parameter and failed to read from config file (/var/mobile/Media/fuwuduan.txt)"} options:0 error:nil];
            return response;
        }
        TVLog(@"Relay: Using serverIP from config file: %@", relayIP);
    }

    NSUInteger port = portStr ? (NSUInteger)[portStr integerValue] : 8183;

    // 角色验证
    if (![role isEqualToString:@"master"] && ![role isEqualToString:@"slave"]) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Role must be 'master' or 'slave'"} options:0 error:nil];
        return response;
    }

    BOOL success = [self connectToRelay:relayIP port:port role:role];

    response.statusCode = success ? 200 : 500;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"success": @(success),
        @"relayMode": @(_relayModeEnabled),
        @"relayConnected": @(_relayConnected),
        @"relayIp": _relayIP ?: @"",
        @"relayPort": @(_relayPort),
        @"role": _relayRole ?: @""
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// POST /api/group/relay/stop
- (TVNCHttpResponse *)handleRelayStop {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    [self disconnectFromRelay];

    response.statusCode = 200;
    response.contentType = @"application/json";
    response.body = [NSJSONSerialization dataWithJSONObject:@{@"success": @YES} options:0 error:nil];
    return response;
}

// GET /api/group/slaves — 返回从控设备 IP 列表
- (TVNCHttpResponse *)handleGroupSlaves {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    NSArray<NSString *> *ips = [self groupSlaveIPs];
    NSMutableArray *slaves = [NSMutableArray array];
    for (NSString *ip in ips) {
        [slaves addObject:@{@"ip": ip}];
    }

    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"slaves": slaves,
        @"count": @(ips.count)
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

// GET /api/group/proxy-screenshot?ip=192.168.x.x&format=jpeg&quality=0.5&scale=0.3
// 代理从从控设备获取截图（解决跨域问题）
- (TVNCHttpResponse *)handleGroupProxyScreenshot:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    NSString *slaveIP = query[@"ip"];
    if (!slaveIP || slaveIP.length == 0) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Missing ip parameter"} options:0 error:nil];
        return response;
    }

    // 从控设备 HTTP 端口（默认 8182）
    NSString *portStr = query[@"port"] ?: @"8182";
    NSString *format = query[@"format"] ?: @"jpeg";
    NSString *quality = query[@"quality"] ?: @"0.5";
    NSString *scale = query[@"scale"] ?: @"0.3";

    // 构造请求 URL
    NSString *urlStr = [NSString stringWithFormat:@"http://%@:%@/api/screenshot?format=%@&quality=%@&scale=%@",
                        slaveIP, portStr, format, quality, scale];
    NSURL *url = [NSURL URLWithString:urlStr];
    if (!url) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Invalid URL"} options:0 error:nil];
        return response;
    }

    // 同步 HTTP 请求（用 NSURLSession + semaphore）
    __block NSData *imageData = nil;
    @try {
        NSMutableURLRequest *req = [NSMutableURLRequest requestWithURL:url];
        req.timeoutInterval = 3.0;
        req.HTTPMethod = @"GET";

        dispatch_semaphore_t sema = dispatch_semaphore_create(0);
        [[[NSURLSession sharedSession] dataTaskWithRequest:req completionHandler:^(NSData *data, NSURLResponse *resp, NSError *err) {
            imageData = data;
            dispatch_semaphore_signal(sema);
        }] resume];
        dispatch_semaphore_wait(sema, dispatch_time(DISPATCH_TIME_NOW, 4 * NSEC_PER_SEC));
    } @catch (NSException *e) {
        TVLog(@"Group proxy screenshot error: %@", e);
    }

    if (imageData && imageData.length > 0) {
        response.statusCode = 200;
        response.contentType = [format isEqualToString:@"png"] ? @"image/png" : @"image/jpeg";
        response.body = imageData;
    } else {
        response.statusCode = 502;
        response.contentType = @"application/json";
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"error": @"Failed to fetch screenshot from slave"} options:0 error:nil];
    }
    return response;
}

// POST /api/alert?message=xxx&title=xxx&duration=5
// 在设备屏幕弹出系统弹窗提示传入的内容
// 参数：
//   message  (必填) 弹窗显示的内容文本
//   title    (可选) 弹窗标题，默认"MatisuXCS"
//   duration (可选) 自动关闭时长（秒），0 或负数表示一直显示不自动关闭，默认 0
- (TVNCHttpResponse *)handleAlert:(NSDictionary *)query {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    NSString *message = query[@"message"];
    if (!message || message.length == 0) {
        response.statusCode = 400;
        response.contentType = @"application/json";
        NSDictionary *result = @{@"success": @NO, @"error": @"Missing message parameter"};
        response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
        return response;
    }

    NSString *title = query[@"title"] ?: @"MatisuXCS";
    NSString *durationStr = query[@"duration"] ?: @"0";
    NSTimeInterval duration = [durationStr doubleValue];

    TVLog(@"HTTP Server: Show alert - title: %@, message: %@, duration: %.1f", title, message, duration);

    // 在主线程显示弹窗
    dispatch_async(dispatch_get_main_queue(), ^{
        @try {
            UIAlertController *alert = [UIAlertController alertControllerWithTitle:title
                                                                     message:message
                                                              preferredStyle:UIAlertControllerStyleAlert];

            [alert addAction:[UIAlertAction actionWithTitle:@"OK" style:UIAlertActionStyleDefault handler:nil]];

            // 获取当前最上层 ViewController
            UIWindow *window = nil;
            if (@available(iOS 13.0, *)) {
                for (UIWindow *w in [UIApplication sharedApplication].connectedScenes) {
                    if ([w isKindOfClass:[UIWindowScene class]]) {
                        UIWindowScene *scene = (UIWindowScene *)w;
                        window = scene.keyWindow;
                        if (window && window.rootViewController) break;
                    }
                }
            }
            if (!window) {
                window = [UIApplication sharedApplication].keyWindow;
            }

            UIViewController *rootVC = window.rootViewController;
            while (rootVC.presentedViewController) {
                rootVC = rootVC.presentedViewController;
            }

            if (rootVC) {
                [rootVC presentViewController:alert animated:YES completion:nil];

                // duration > 0 时自动关闭弹窗
                if (duration > 0) {
                    dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(duration * NSEC_PER_SEC)),
                                   dispatch_get_main_queue(), ^{
                        [alert dismissViewControllerAnimated:YES completion:nil];
                    });
                }
            } else {
                TVLog(@"HTTP Server: Cannot show alert - no rootViewController");
            }
        } @catch (NSException *e) {
            TVLog(@"HTTP Server: Show alert exception: %@", e);
        }
    });

    response.statusCode = 200;
    response.contentType = @"application/json";
    NSDictionary *result = @{
        @"success": @YES,
        @"message": @"Alert shown",
        @"title": title,
        @"duration": @(duration)
    };
    response.body = [NSJSONSerialization dataWithJSONObject:result options:0 error:nil];
    return response;
}

