    "<div class='stats'>"
    "<div class='stat-card'><div class='label'>从控数量</div><div class='value' id='slaveCount'>0</div></div>"
    "<div class='stat-card'><div class='label'>发送事件</div><div class='value' id='sendCount'>0</div></div>"
    "<div class='stat-card'><div class='label'>接收事件</div><div class='value' id='recvCount'>0</div></div>"
    "</div>"
    
    "<div class='panel'>"
    "<h2>触摸操作区（主控模式下，在此区域触摸/滑动发送事件）</h2>"
    "<div class='touch-area' id='touchArea'></div>"
    "<div class='btn-row' style='margin-top:10px'>"
    "<button class='btn btn-primary' onclick='sendClick(0.5,0.5)'>点击中心</button>"
    "<button class='btn btn-primary' onclick='sendClick(0.25,0.25)'>左上</button>"
    "<button class='btn btn-primary' onclick='sendClick(0.75,0.75)'>右下</button>"
    "<button class='btn btn-warn' onclick='sendHome()'>Home键</button>"
    "<button class='btn btn-warn' onclick='sendPower()'>电源键</button>"
    "<button class='btn btn-danger' onclick='clearLog()'>清空日志</button>"
    "</div>"
    "</div>"
    
    "<div class='panel'>"
    "<h2>事件日志</h2>"
    "<div class='log-area' id='logArea'></div>"
    "</div>"
    
    "<script>"
    "var ws = null;"
    "var sendCounter = 0, recvCounter = 0;"
    "var touchActive = false, lastTouchX = 0, lastTouchY = 0;"
    ""
    "function log(msg, isError) {"
    "  var area = document.getElementById('logArea');"
    "  var now = new Date().toLocaleTimeString();"
    "  var div = document.createElement('div');"
    "  div.className = 'log-entry' + (isError ? ' error' : '');"
    "  div.innerHTML = '<span class=\\'time\\'>' + now + '</span> ' + msg;"
    "  area.appendChild(div);"
    "  area.scrollTop = area.scrollHeight;"
    "}"
    ""
    "function updateStatus(text, color) {"
    "  var el = document.getElementById('connStatus');"
    "  el.textContent = text;"
    "  el.style.color = color || '#eee';"
    "}"
    ""
    "function connectWS() {"
    "  if (ws && ws.readyState <= 1) { log('已连接，先断开', true); return; }"
    "  var ip = document.getElementById('deviceIp').value;"
    "  var port = document.getElementById('wsPort').value;"
    "  if (!ip) { log('请输入设备 IP', true); return; }"
    "  var url = 'ws://' + ip + ':' + port;"
    "  log('连接 ' + url + ' ...');"
    "  ws = new WebSocket(url);"
    "  ws.onopen = function() {"
    "    updateStatus('已连接 (WebSocket)', '#52c41a');"
    "    log('WebSocket 连接成功');"
    "  };"
    "  ws.onmessage = function(e) {"
    "    recvCounter++;"
    "    document.getElementById('recvCount').textContent = recvCounter;"
    "    log('收到: <span class=\\'data\\'>' + e.data + '</span>');"
    "    try {"
    "      var ev = JSON.parse(e.data);"
    "      if (ev.type === 'touch') {"
    "        showDot(ev.x, ev.y);"
    "      }"
    "    } catch(ex) {}"
    "  };"
    "  ws.onclose = function() {"
    "    updateStatus('已断开', '#ff4d4f');"
    "    log('WebSocket 连接关闭');"
    "  };"
    "  ws.onerror = function() {"
    "    updateStatus('连接失败', '#ff4d4f');"
    "    log('WebSocket 连接失败', true);"
    "  };"
    "}"
    ""
    "function disconnectWS() {"
    "  if (ws) { ws.close(); ws = null; }"
    "  updateStatus('已断开', '#ff4d4f');"
    "}"
    ""
    "function onModeChange() {"
    "  var mode = document.getElementById('mode').value;"
    "  document.getElementById('slaveConnectRow').style.display = mode === 'slave' ? 'flex' : 'none';"
    "}"
    ""
    "function startGroup() {"
    "  var ip = document.getElementById('deviceIp').value;"
    "  var port = document.getElementById('wsPort').value;"
    "  var mode = document.getElementById('mode').value;"
    "  var master = mode === 'master' ? '1' : '0';"
    "  var url = 'http://' + ip + ':8182/api/group/start?master=' + master + '&port=' + port;"
    "  fetch(url, {method:'POST'}).then(r=>r.json()).then(d => {"
    "    log('群控启动: ' + JSON.stringify(d));"
    "    if (d.success) updateStatus('群控运行中 (' + (d.master ? '主控' : '从控') + ')', '#52c41a');"
    "  }).catch(e => log('启动失败: ' + e, true));"
    "}"
    ""
    "function stopGroup() {"
    "  var ip = document.getElementById('deviceIp').value;"
    "  fetch('http://' + ip + ':8182/api/group/stop', {method:'POST'}).then(r=>r.json()).then(d => {"
    "    log('群控停止: ' + JSON.stringify(d));"
    "    updateStatus('群控已停止', '#faad14');"
    "  }).catch(e => log('停止失败: ' + e, true));"
    "}"
    ""
    "function connectToMaster() {"
    "  var ip = document.getElementById('deviceIp').value;"
    "  var masterIp = document.getElementById('masterIp').value;"
    "  var port = document.getElementById('wsPort').value;"
    "  if (!masterIp) { log('请输入主控 IP', true); return; }"
    "  fetch('http://' + ip + ':8182/api/group/connect?ip=' + masterIp + '&port=' + port, {method:'POST'}).then(r=>r.json()).then(d => {"
    "    log('连接主控: ' + JSON.stringify(d));"
    "    if (d.success) updateStatus('从控已连接到主控 ' + masterIp, '#52c41a');"
    "  }).catch(e => log('连接失败: ' + e, true));"
    "}"
    ""
    "function disconnectFromMaster() {"
    "  var ip = document.getElementById('deviceIp').value;"
    "  fetch('http://' + ip + ':8182/api/group/disconnect', {method:'POST'}).then(r=>r.json()).then(d => {"
    "    log('断开主控: ' + JSON.stringify(d));"
    "    updateStatus('已断开主控', '#faad14');"
    "  }).catch(e => log('断开失败: ' + e, true));"
    "}"
    ""
    "function sendEvent(obj) {"
    "  var json = JSON.stringify(obj);"
    "  if (ws && ws.readyState === 1) {"
    "    ws.send(json);"
    "    sendCounter++;"
    "    document.getElementById('sendCount').textContent = sendCounter;"
    "    log('发送: <span class=\\'data\\'>' + json + '</span>');"
    "  } else {"
    "    log('WebSocket 未连接', true);"
    "  }"
    "}"
    ""
    "function sendClick(nx, ny) {"
    "  sendEvent({type:'touch', x:nx, y:ny, action:'down'});"
    "  setTimeout(function() { sendEvent({type:'touch', x:nx, y:ny, action:'up'}); }, 50);"
    "}"
    ""
    "function sendHome() {"
    "  sendEvent({type:'key', action:'home_down'});"
    "  setTimeout(function() { sendEvent({type:'key', action:'home_up'}); }, 50);"
    "}"
    ""
    "function sendPower() {"
    "  sendEvent({type:'key', action:'power_down'});"
    "  setTimeout(function() { sendEvent({type:'key', action:'power_up'}); }, 50);"
    "}"
    ""
    "function showDot(nx, ny) {"
    "  var area = document.getElementById('touchArea');"
    "  var dot = document.createElement('div');"
    "  dot.className = 'dot';"
    "  dot.style.left = (nx * 100) + '%';"
    "  dot.style.top = (ny * 100) + '%';"
    "  dot.style.opacity = '1';"
    "  area.appendChild(dot);"
    "  setTimeout(function() { dot.style.opacity = '0'; dot.style.transition = 'opacity 0.5s'; }, 300);"
    "  setTimeout(function() { area.removeChild(dot); }, 800);"
    "}"
    ""
    "// 触摸区域事件"
    "var touchArea = document.getElementById('touchArea');"
    ""
    "function getNormPos(e) {"
    "  var rect = touchArea.getBoundingClientRect();"
    "  var clientX, clientY;"
    "  if (e.touches && e.touches.length > 0) {"
    "    clientX = e.touches[0].clientX; clientY = e.touches[0].clientY;"
    "  } else {"
    "    clientX = e.clientX; clientY = e.clientY;"
    "  }"
    "  return {"
    "    x: (clientX - rect.left) / rect.width,"
    "    y: (clientY - rect.top) / rect.height"
    "  };"
    "}"
    ""
    "touchArea.addEventListener('mousedown', function(e) {"
    "  touchActive = true;"
    "  var p = getNormPos(e);"
    "  lastTouchX = p.x; lastTouchY = p.y;"
    "  sendEvent({type:'touch', x:p.x, y:p.y, action:'down'});"
    "  showDot(p.x, p.y);"
    "});"
    ""
    "touchArea.addEventListener('mousemove', function(e) {"
    "  if (!touchActive) return;"
    "  var p = getNormPos(e);"
    "  if (Math.abs(p.x - lastTouchX) < 0.01 && Math.abs(p.y - lastTouchY) < 0.01) return;"
    "  lastTouchX = p.x; lastTouchY = p.y;"
    "  sendEvent({type:'touch', x:p.x, y:p.y, action:'move'});"
    "  showDot(p.x, p.y);"
    "});"
    ""
    "touchArea.addEventListener('mouseup', function(e) {"
    "  if (!touchActive) return;"
    "  touchActive = false;"
    "  var p = getNormPos(e);"
    "  sendEvent({type:'touch', x:p.x, y:p.y, action:'up'});"
    "});"
    ""
    "touchArea.addEventListener('touchstart', function(e) {"
    "  e.preventDefault();"
    "  var p = getNormPos(e);"
    "  lastTouchX = p.x; lastTouchY = p.y;"
    "  sendEvent({type:'touch', x:p.x, y:p.y, action:'down'});"
    "  showDot(p.x, p.y);"
    "});"
    ""
    "touchArea.addEventListener('touchmove', function(e) {"
    "  e.preventDefault();"
    "  var p = getNormPos(e);"
    "  if (Math.abs(p.x - lastTouchX) < 0.01 && Math.abs(p.y - lastTouchY) < 0.01) return;"
    "  lastTouchX = p.x; lastTouchY = p.y;"
    "  sendEvent({type:'touch', x:p.x, y:p.y, action:'move'});"
    "  showDot(p.x, p.y);"
    "});"
    ""
    "touchArea.addEventListener('touchend', function(e) {"
    "  e.preventDefault();"
    "  sendEvent({type:'touch', x:lastTouchX, y:lastTouchY, action:'up'});"
    "});"
    ""
    "function clearLog() {"
    "  document.getElementById('logArea').innerHTML = '';"
    "}"
    ""
    "// 定期刷新状态"
    "setInterval(function() {"
    "  var ip = document.getElementById('deviceIp').value;"
    "  if (!ip) return;"
    "  fetch('http://' + ip + ':8182/api/group/status').then(r=>r.json()).then(d => {"
    "    document.getElementById('slaveCount').textContent = d.slaves || 0;"
    "  }).catch(function(){});"
    "}, 3000);"
    "</script>"
    "</body></html>";
    
    response.statusCode = 200;
    response.contentType = @"text/html; charset=utf-8";
    response.body = [html dataUsingEncoding:NSUTF8StringEncoding];
    return response;
}

// GET /group-control — 投屏群控页面
- (TVNCHttpResponse *)handleGroupControlPage {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];

    NSString *html = @"<!DOCTYPE html>"
    "<html lang='zh-CN'><head>"
    "<meta charset='UTF-8'>"
    "<meta name='viewport' content='width=device-width, initial-scale=1.0, user-scalable=no'>"
    "<title>TrollVNC 投屏群控</title>"
    "<style>"
    "* { margin: 0; padding: 0; box-sizing: border-box; }"
    "body { font-family: -apple-system, BlinkMacSystemFont, sans-serif; background: #0a0a1a; color: #eee; overflow: hidden; height: 100vh; }"
    ".toolbar { background: #16213e; padding: 8px 16px; display: flex; align-items: center; gap: 10px; border-bottom: 1px solid #333; flex-shrink: 0; }"
    ".toolbar h1 { font-size: 16px; font-weight: 600; color: #667eea; margin-right: auto; }"
    ".toolbar input { padding: 5px 10px; border-radius: 6px; border: 1px solid #444; background: #0f3460; color: #eee; font-size: 13px; width: 140px; }"
    ".toolbar select { padding: 5px 10px; border-radius: 6px; border: 1px solid #444; background: #0f3460; color: #eee; font-size: 13px; }"
    ".btn { padding: 5px 14px; border: none; border-radius: 6px; cursor: pointer; font-size: 13px; transition: all 0.2s; }"
    ".btn-primary { background: #667eea; color: white; }"
    ".btn-primary:hover { background: #5568d3; }"
    ".btn-success { background: #52c41a; color: white; }"
    ".btn-danger { background: #ff4d4f; color: white; }"
    ".btn-sm { padding: 3px 10px; font-size: 12px; }"
    ".status-dot { width: 8px; height: 8px; border-radius: 50%; display: inline-block; margin-right: 4px; }"
    ".status-dot.on { background: #52c41a; }"
    ".status-dot.off { background: #666; }"
    ".main { display: flex; flex: 1; overflow: hidden; height: calc(100vh - 46px); }"
    ".master-panel { flex: 1; display: flex; flex-direction: column; min-width: 0; position: relative; }"
    ".master-label { background: #1a1a2e; padding: 4px 12px; font-size: 12px; color: #667eea; display: flex; align-items: center; gap: 6px; }"
    ".master-screen { flex: 1; display: flex; align-items: center; justify-content: center; background: #0a0a1a; position: relative; overflow: hidden; }"
    ".master-screen img { max-width: 100%; max-height: 100%; object-fit: contain; cursor: crosshair; touch-action: none; user-select: none; -webkit-user-select: none; }"
    ".slave-panel { width: 220px; background: #0f0f1a; border-left: 1px solid #333; overflow-y: auto; flex-shrink: 0; }"
    ".slave-item { padding: 8px; border-bottom: 1px solid #1a1a2e; }"
    ".slave-item .label { font-size: 11px; color: #888; margin-bottom: 4px; display: flex; align-items: center; gap: 4px; }"
    ".slave-item img { width: 100%; border-radius: 4px; background: #111; display: block; }"
    ".slave-item img.error { min-height: 80px; opacity: 0.3; }"
    ".no-slave { padding: 20px 10px; text-align: center; color: #555; font-size: 12px; }"
    ".log-panel { position: absolute; bottom: 0; left: 0; right: 0; background: rgba(0,0,0,0.85); max-height: 120px; overflow-y: auto; font-size: 11px; font-family: monospace; padding: 6px 10px; display: none; border-top: 1px solid #333; }"
    ".log-panel.show { display: block; }"
    ".log-panel .log-line { color: #667eea; padding: 1px 0; }"
    ".log-panel .log-line.err { color: #ff4d4f; }"
    ".fps-badge { position: absolute; top: 4px; right: 4px; background: rgba(0,0,0,0.7); color: #52c41a; font-size: 11px; padding: 2px 6px; border-radius: 4px; font-family: monospace; }"
    "</style></head><body>"

    "<div class='toolbar'>"
    "<h1>TrollVNC 投屏群控</h1>"
    "<span id='statusDot' class='status-dot off'></span>"
    "<span id='statusText' style='font-size:12px;color:#888'>未连接</span>"
    "<label style='font-size:12px;color:#888'>主控IP:</label>"
    "<input type='text' id='masterIp' placeholder='192.168.x.x'>"
    "<button class='btn btn-success btn-sm' onclick='startControl()'>启动群控</button>"
    "<button class='btn btn-danger btn-sm' onclick='stopControl()'>停止</button>"
    "<button class='btn btn-primary btn-sm' onclick='toggleLog()'>日志</button>"
    "</div>"

    "<div class='main'>"
    "<div class='master-panel'>"
    "<div class='master-label'>"
    "<span class='status-dot on'></span> 主控画面（在此操作，从控同步跟随）"
    "<span id='slaveInfo' style='margin-left:auto;color:#888'>从控: 0</span>"
    "</div>"
    "<div class='master-screen' id='masterScreen'>"
    "<img id='masterImg' src='' alt='主控画面' style='display:none'>"
    "<div id='masterPlaceholder' style='color:#444;font-size:14px'>请输入主控IP并点击启动群控</div>"
    "<div class='fps-badge' id='fpsBadge' style='display:none'>0 fps</div>"
    "</div>"
    "<div class='log-panel' id='logPanel'></div>"
    "</div>"
    "<div class='slave-panel' id='slavePanel'>"
    "<div class='no-slave' id='noSlave'>等待从控设备连接...</div>"
    "</div>"
    "</div>"

    "<script>"
    "var ws = null;"
    "var masterIp = '';"
    "var masterInterval = null;"
    "var slaveInterval = null;"
    "var slaveList = [];"
    "var frameCount = 0;"
    "var lastFpsTime = Date.now();"
    "var logVisible = false;"

    "function log(msg, isErr) {"
    "  var p = document.getElementById('logPanel');"
    "  var d = document.createElement('div');"
    "  d.className = 'log-line' + (isErr ? ' err' : '');"
    "  d.textContent = new Date().toLocaleTimeString() + ' ' + msg;"
    "  p.appendChild(d);"
    "  if (p.children.length > 100) p.removeChild(p.firstChild);"
    "  p.scrollTop = p.scrollHeight;"
    "}"

    "function toggleLog() {"
    "  logVisible = !logVisible;"
    "  document.getElementById('logPanel').className = 'log-panel' + (logVisible ? ' show' : '');"
    "}"

    "function setStatus(on, text) {"
    "  document.getElementById('statusDot').className = 'status-dot ' + (on ? 'on' : 'off');"
    "  document.getElementById('statusText').textContent = text;"
    "}"

    "function startControl() {"
    "  masterIp = document.getElementById('masterIp').value.trim();"
    "  if (!masterIp) { alert('请输入主控设备IP'); return; }"

    "  // 1. 启动群控 WS Server"
    "  fetch('http://' + masterIp + ':8182/api/group/start?master=1&port=8183', {method:'POST'})"
    "    .then(r=>r.json()).then(d => {"
    "      log('群控已启动: master=' + d.master + ', port=' + d.port);"
    "      setStatus(true, '群控已启动');"
    "    }).catch(e => log('启动群控失败: ' + e.message, true));"

    "  // 2. 连接 WS"
    "  if (ws) ws.close();"
    "  ws = new WebSocket('ws://' + masterIp + ':8183');"
    "  ws.onopen = function() { log('WS 已连接'); };"
    "  ws.onmessage = function(e) { log('WS 收到: ' + e.data); };"
    "  ws.onerror = function() { log('WS 错误', true); };"
    "  ws.onclose = function() { log('WS 断开'); setStatus(false, 'WS 断开'); };"

    "  // 3. 开始截图轮询 - 主控"
    "  if (masterInterval) clearInterval(masterInterval);"
    "  document.getElementById('masterImg').style.display = 'block';"
    "  document.getElementById('masterPlaceholder').style.display = 'none';"
    "  document.getElementById('fpsBadge').style.display = 'block';"
    "  masterInterval = setInterval(refreshMaster, 400);"

    "  // 4. 开始轮询从控列表"
    "  if (slaveInterval) clearInterval(slaveInterval);"
    "  slaveInterval = setInterval(refreshSlaves, 3000);"
    "  refreshSlaves();"
    "}"

    "function stopControl() {"
    "  if (ws) { ws.close(); ws = null; }"
    "  if (masterInterval) { clearInterval(masterInterval); masterInterval = null; }"
    "  if (slaveInterval) { clearInterval(slaveInterval); slaveInterval = null; }"
    "  document.getElementById('masterImg').style.display = 'none';"
    "  document.getElementById('masterPlaceholder').style.display = 'block';"
    "  document.getElementById('fpsBadge').style.display = 'none';"
    "  setStatus(false, '已停止');"
    "  fetch('http://' + masterIp + ':8182/api/group/stop', {method:'POST'}).catch(function(){});"
    "}"

    "function refreshMaster() {"
    "  var img = document.getElementById('masterImg');"
    "  var url = 'http://' + masterIp + ':8182/api/screenshot?format=jpeg&quality=0.7&scale=0.5&_t=' + Date.now();"
    "  img.src = url;"
    "  frameCount++;"
    "  var now = Date.now();"
    "  if (now - lastFpsTime >= 1000) {"
    "    document.getElementById('fpsBadge').textContent = frameCount + ' fps';"
    "    frameCount = 0;"
    "    lastFpsTime = now;"
    "  }"
    "}"

    "var knownSlaves = {};"

    "function refreshSlaves() {"
    "  fetch('http://' + masterIp + ':8182/api/group/slaves').then(r=>r.json()).then(d => {"
    "    document.getElementById('slaveInfo').textContent = '从控: ' + d.count;"
    "    var panel = document.getElementById('slavePanel');"
    "    var noSlave = document.getElementById('noSlave');"
    "    if (d.count === 0) {"
    "      noSlave.style.display = 'block';"
    "      return;"
    "    }"
    "    noSlave.style.display = 'none';"
    "    // 添加新的从控"
    "    for (var i = 0; i < d.slaves.length; i++) {"
    "      var ip = d.slaves[i].ip;"
    "      if (!knownSlaves[ip]) {"
    "        knownSlaves[ip] = true;"
    "        var div = document.createElement('div');"
    "        div.className = 'slave-item';"
    "        div.id = 'slave-' + ip.replace(/\\./g, '-');"
    "        div.innerHTML = '<div class=\\'label\\'><span class=\\'status-dot on\\'></span>' + ip + '</div><img id=\\'simg-' + ip.replace(/\\./g, '-') + '\\' src=\\'\\' class=\\'error\\'>';"
    "        panel.appendChild(div);"
    "      }"
    "    }"
    "    // 刷新从控截图"
    "    for (var i = 0; i < d.slaves.length; i++) {"
    "      var ip = d.slaves[i].ip;"
    "      var imgId = 'simg-' + ip.replace(/\\./g, '-');"
    "      var sImg = document.getElementById(imgId);"
    "      if (sImg) {"
    "        sImg.src = 'http://' + masterIp + ':8182/api/group/proxy-screenshot?ip=' + ip + '&format=jpeg&quality=0.5&scale=0.3&_t=' + Date.now();"
    "        sImg.className = '';"
    "        sImg.onerror = function() { this.className = 'error'; };"
    "      }"
    "    }"
    "  }).catch(function(){});"
    "}"

    // 触摸事件处理 - 发送到主控 WS
    "var masterImg = document.getElementById('masterImg');"
    "var touching = false;"

    "function getNormPos(e) {"
    "  var rect = masterImg.getBoundingClientRect();"
    "  var x, y;"
    "  if (e.touches) {"
    "    x = e.touches[0].clientX - rect.left;"
    "    y = e.touches[0].clientY - rect.top;"
    "  } else {"
    "    x = e.clientX - rect.left;"
    "    y = e.clientY - rect.top;"
    "  }"
    "  return { x: x / rect.width, y: y / rect.height };"
    "}"

    "function sendTouch(action, nx, ny) {"
    "  if (!ws || ws.readyState !== 1) return;"
    "  var evt = JSON.stringify({type:'touch', x: nx, y: ny, action: action});"
    "  ws.send(evt);"
    "  log('Touch: ' + action + ' (' + nx.toFixed(3) + ', ' + ny.toFixed(3) + ')');"
    "}"

    "masterImg.addEventListener('mousedown', function(e) {"
    "  e.preventDefault(); touching = true;"
    "  var p = getNormPos(e);"
    "  sendTouch('down', p.x, p.y);"
    "});"
    "document.addEventListener('mousemove', function(e) {"
    "  if (!touching) return;"
    "  var p = getNormPos(e);"
    "  sendTouch('move', p.x, p.y);"
    "});"
    "document.addEventListener('mouseup', function(e) {"
    "  if (!touching) return; touching = false;"
    "  var p = getNormPos(e);"
    "  sendTouch('up', p.x, p.y);"
    "});"
    "masterImg.addEventListener('touchstart', function(e) {"
    "  e.preventDefault(); touching = true;"
    "  var p = getNormPos(e);"
    "  sendTouch('down', p.x, p.y);"
    "}, {passive: false});"
    "masterImg.addEventListener('touchmove', function(e) {"
    "  e.preventDefault();"
    "  var p = getNormPos(e);"
    "  sendTouch('move', p.x, p.y);"
    "}, {passive: false});"
    "masterImg.addEventListener('touchend', function(e) {"
    "  e.preventDefault(); touching = false;"
    "  sendTouch('up', 0, 0);"
    "}, {passive: false});"
    "</script>"
    "</body></html>";

    response.statusCode = 200;
    response.contentType = @"text/html; charset=utf-8";
    response.body = [html dataUsingEncoding:NSUTF8StringEncoding];
    return response;
}

@end

#pragma mark - TVNCHttpConnection

@implementation TVNCHttpConnection

- (void)handle {
    // 设置接收超时（5分钟，支持大文件上传）
    struct timeval tv;
    tv.tv_sec = 300;
    tv.tv_usec = 0;
    setsockopt(_clientSocket, SOL_SOCKET, SO_RCVTIMEO, &tv, sizeof(tv));
    
    // 预声明变量（避免 goto 跳过初始化）
    NSString *clientAddr = nil;
    struct sockaddr_in peerAddr;
    socklen_t peerLen = sizeof(peerAddr);
    TVNCHttpResponse *response = nil;
    NSData *body = nil;
    
    // 读取请求头
    NSMutableData *headerData = [NSMutableData data];
    uint8_t buffer[8192];
    NSInteger totalReceived = 0;
    NSInteger maxHeaderSize = 64 * 1024; // 最大 64KB 头部
    NSRange headerEndRange = NSMakeRange(NSNotFound, 0);
    
    // 先读取头部（直到 \r\n\r\n）
    while (totalReceived < maxHeaderSize) {
        ssize_t n = recv(_clientSocket, buffer, sizeof(buffer), 0);
        if (n <= 0) break;
        
        [headerData appendBytes:buffer length:n];
        totalReceived += n;
        
        // 查找头部结束标记
        headerEndRange = [headerData rangeOfData:[@"\r\n\r\n" dataUsingEncoding:NSUTF8StringEncoding]
                                         options:0
                                           range:NSMakeRange(0, headerData.length)];
        if (headerEndRange.location != NSNotFound) {
            break;
        }
    }
    
    if (headerEndRange.location == NSNotFound) {
        TVLog(@"HTTP Server: Failed to receive complete headers");
        close(_clientSocket);
        return;
    }
    
    // 解析请求头
    NSUInteger headerLength = headerEndRange.location + headerEndRange.length;
    NSString *headerStr = [[NSString alloc] initWithBytes:headerData.bytes
                                                   length:headerLength
                                                 encoding:NSUTF8StringEncoding];
    NSArray *lines = [headerStr componentsSeparatedByString:@"\r\n"];
    if (lines.count == 0) {
        TVLog(@"HTTP Server: Empty request");
        close(_clientSocket);
        return;
    }
    
    // 解析请求行
    NSArray *requestParts = [lines[0] componentsSeparatedByString:@" "];
    if (requestParts.count < 2) {
        TVLog(@"HTTP Server: Invalid request line: %@", lines[0]);
        close(_clientSocket);
        return;
    }
    
    NSString *method = requestParts[0];
    NSString *fullPath = requestParts[1];
    
    // 解析路径和查询参数
    NSString *path = fullPath;
    NSMutableDictionary *query = [NSMutableDictionary dictionary];
    NSRange queryRange = [fullPath rangeOfString:@"?"];
    if (queryRange.location != NSNotFound) {
        path = [fullPath substringToIndex:queryRange.location];
        NSString *queryString = [fullPath substringFromIndex:queryRange.location + 1];
        NSArray *pairs = [queryString componentsSeparatedByString:@"&"];
        for (NSString *pair in pairs) {
            NSArray *kv = [pair componentsSeparatedByString:@"="];
            if (kv.count == 2) {
                NSString *key = [kv[0] stringByRemovingPercentEncoding];
                NSString *value = [kv[1] stringByRemovingPercentEncoding];
                query[key] = value;
            }
        }
    }
    
    // 解析 Content-Length
    NSInteger contentLength = 0;
    for (NSString *line in lines) {
        if ([line hasPrefix:@"Content-Length: "]) {
            NSString *lenStr = [line substringFromIndex:16];
            contentLength = [lenStr integerValue];
            break;
        }
    }
    
    // 解析所有请求头
    NSMutableDictionary *headers = [NSMutableDictionary dictionary];
    for (NSUInteger i = 1; i < lines.count; i++) {
        NSString *line = lines[i];
        NSRange colonRange = [line rangeOfString:@": "];
        if (colonRange.location != NSNotFound && colonRange.location > 0) {
            NSString *key = [line substringToIndex:colonRange.location];
            NSString *value = [line substringFromIndex:colonRange.location + 2];
            headers[key] = value;
        }
    }
    self.parsedHeaders = headers;
    
    TVLog(@"HTTP Server: %@ %@ (Content-Length: %ld)", method, fullPath, (long)contentLength);
    
    // 处理 body
    NSInteger maxMemorySize = 10 * 1024 * 1024; // 10MB 以下直接读入内存
    
    // 检查是否已有部分 body 数据（在头部之后）
    NSInteger bodyReceived = headerData.length - headerLength;
    NSMutableData *bodyData = [NSMutableData data];
    if (bodyReceived > 0) {
        [bodyData appendBytes:((uint8_t *)headerData.bytes + headerLength) length:bodyReceived];
    }
    
    // 对于大文件上传，使用流式处理（避免全量缓存到内存再写文件）
    BOOL isUploadRequest = [path isEqualToString:@"/api/upload"];
    BOOL isWebDAVPut = ([method isEqualToString:@"PUT"] && [path hasPrefix:@"/webdav"]);
    NSString *tempFilePath = nil;
    int tempFileFd = -1;
    NSString *webdavTargetPath = nil; // WebDAV PUT 直接写入的目标路径（非临时）

    // WebDAV PUT：直接打开目标文件，流式写入
    if (isWebDAVPut && contentLength > maxMemorySize) {
        // 复用 webdavFilePathForPath 的逻辑，计算目标路径
        // 使用 self.server.webdavRootPath 获取正确路径（TVNCHttpConnection 独立于 TVNCHttpServer）
        NSString *rawRelPath = [path substringFromIndex:8];
        NSString *decodedRelPath = [rawRelPath stringByRemovingPercentEncoding] ?: rawRelPath;
        NSString *targetPath = [self.server.webdavRootPath stringByAppendingPathComponent:decodedRelPath];
        // 确保目录存在
        NSString *dirPath = [targetPath stringByDeletingLastPathComponent];
        [[NSFileManager defaultManager] createDirectoryAtPath:dirPath withIntermediateDirectories:YES attributes:nil error:nil];
        // 使用 .tmp 后缀，传输完成后 rename 生效（原子操作）
        webdavTargetPath = [targetPath stringByAppendingString:@".tmp"];
        tempFileFd = open([webdavTargetPath UTF8String], O_WRONLY | O_CREAT | O_TRUNC, 0644);
        if (tempFileFd >= 0 && bodyData.length > 0) {
            write(tempFileFd, bodyData.bytes, bodyData.length);
        }
        NSInteger remaining = contentLength - bodyReceived;
        while (remaining > 0 && tempFileFd >= 0) {
            ssize_t toRead = sizeof(buffer);
            if (toRead > remaining) toRead = remaining;
            ssize_t n = recv(_clientSocket, buffer, toRead, 0);
            if (n <= 0) break;
            write(tempFileFd, buffer, n);
            remaining -= n;
        }
        if (tempFileFd >= 0) {
            close(tempFileFd);
            tempFileFd = -1;
        }
        // 原子 rename：.tmp → 正式路径
        if (webdavTargetPath && [[NSFileManager defaultManager] fileExistsAtPath:webdavTargetPath]) {
            [[NSFileManager defaultManager] removeItemAtPath:targetPath error:nil];
            [[NSFileManager defaultManager] moveItemAtPath:webdavTargetPath toPath:targetPath error:nil];
        }
        // 返回成功响应（跳过下方 handleRequest，直接发送响应）
        TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
        response.statusCode = 201;
        response.contentType = @"text/plain";
        response.body = [@"Created" dataUsingEncoding:NSUTF8StringEncoding];
        goto send_response;
    } else if (isUploadRequest && contentLength > maxMemorySize) {
        // 大文件上传：使用临时文件
        tempFilePath = [NSTemporaryDirectory() stringByAppendingPathComponent:[NSString stringWithFormat:@"upload_%ld", (long)time(NULL)]];
        tempFileFd = open([tempFilePath UTF8String], O_WRONLY | O_CREAT | O_TRUNC, 0644);
        
        if (tempFileFd >= 0 && bodyData.length > 0) {
            write(tempFileFd, bodyData.bytes, bodyData.length);
        }
        
        // 继续接收剩余数据到临时文件
        NSInteger remaining = contentLength - bodyReceived;
        while (remaining > 0 && tempFileFd >= 0) {
            ssize_t toRead = sizeof(buffer);
            if (toRead > remaining) toRead = remaining;
            
            ssize_t n = recv(_clientSocket, buffer, toRead, 0);
            if (n <= 0) break;
            
            write(tempFileFd, buffer, n);
            remaining -= n;
        }
        
        if (tempFileFd >= 0) {
            close(tempFileFd);
            // 读取临时文件内容
            body = [NSData dataWithContentsOfFile:tempFilePath];
            // 删除临时文件
            unlink([tempFilePath UTF8String]);
        }
    } else {
        // 小文件或其他请求：读入内存
        // 如果 Content-Length > 0，按长度读取；否则读取直到连接关闭
        if (contentLength > 0) {
            NSInteger remaining = contentLength - bodyReceived;
            while (remaining > 0) {
                ssize_t toRead = sizeof(buffer);
                if (toRead > remaining) toRead = remaining;
                
                ssize_t n = recv(_clientSocket, buffer, toRead, 0);
                if (n <= 0) break;
                
                [bodyData appendBytes:buffer length:n];
                remaining -= n;
            }
        } else if (([method isEqualToString:@"POST"] || [method isEqualToString:@"PUT"]) && bodyReceived > 0) {
            // 有 body 但 Content-Length 为 0，读取直到超时或连接关闭
            // 设置短超时用于检测 body 结束
            struct timeval shortTv;
            shortTv.tv_sec = 1;
            shortTv.tv_usec = 0;
            setsockopt(_clientSocket, SOL_SOCKET, SO_RCVTIMEO, &shortTv, sizeof(shortTv));
            
            while (true) {
                ssize_t n = recv(_clientSocket, buffer, sizeof(buffer), 0);
                if (n <= 0) break;
                [bodyData appendBytes:buffer length:n];
                // 限制最大读取 10MB
                if (bodyData.length > maxMemorySize) break;
            }
            
            // 恢复长超时
            struct timeval longTv;
            longTv.tv_sec = 300;
            longTv.tv_usec = 0;
            setsockopt(_clientSocket, SOL_SOCKET, SO_RCVTIMEO, &longTv, sizeof(longTv));
        }
        
        body = bodyData;
    }
    
    // 获取客户端 IP 地址
    if (getpeername(_clientSocket, (struct sockaddr *)&peerAddr, &peerLen) == 0) {
        char ipStr[INET_ADDRSTRLEN];
        inet_ntop(AF_INET, &peerAddr.sin_addr, ipStr, INET_ADDRSTRLEN);
        clientAddr = [NSString stringWithUTF8String:ipStr];
    }
    
    // 处理请求
    if (!isWebDAVPut || contentLength <= maxMemorySize) {
        response = [_server handleRequest:method path:path query:query body:body clientAddr:clientAddr headers:_parsedHeaders];
    }
    
    // 发送响应
    // MJPEG 流特殊处理：检测 __MJPEG_STREAM__ 标记
    if (response && [response.contentType hasPrefix:@"multipart/x-mixed-replace"] &&
        response.body.length > 17 &&
        [[NSString alloc] initWithBytes:response.body.bytes length:17 encoding:NSUTF8StringEncoding] != nil) {
        NSString *bodyStr = [[NSString alloc] initWithData:response.body encoding:NSUTF8StringEncoding];
        if (bodyStr && [bodyStr hasPrefix:@"__MJPEG_STREAM__"]) {
            // 解析 MJPEG 参数
            NSData *jsonPart = [bodyStr dataUsingEncoding:NSUTF8StringEncoding];
            jsonPart = [jsonPart subdataWithRange:NSMakeRange(17, jsonPart.length - 17)];
            NSDictionary *params = [NSJSONSerialization JSONObjectWithData:jsonPart options:0 error:nil];

            CGFloat mjpegQuality = [params[@"q"] floatValue];
            if (mjpegQuality <= 0) mjpegQuality = 0.6;
            if (mjpegQuality > 1.0) mjpegQuality = 1.0;
            CGFloat mjpegScale = [params[@"scale"] floatValue];
            if (mjpegScale <= 0) mjpegScale = 1.0;
            if (mjpegScale > 1.0) mjpegScale = 1.0;
            int mjpegFps = [params[@"fps"] intValue];
            if (mjpegFps < 1) mjpegFps = 10;
            if (mjpegFps > 30) mjpegFps = 30;
            int mjpegMaxW = [params[@"maxw"] intValue];
            int mjpegMaxH = [params[@"maxh"] intValue];

            // 发送 MJPEG 流头部（不发送 Content-Length，使用 chunked 或持续推送）
            NSString *mjpegHeader = [NSString stringWithFormat:
                @"HTTP/1.1 200 OK\r\n"
                @"Content-Type: multipart/x-mixed-replace; boundary=frameboundary\r\n"
                @"Cache-Control: no-cache, no-store, must-revalidate\r\n"
                @"Pragma: no-cache\r\n"
                @"Connection: close\r\n"
                @"Access-Control-Allow-Origin: *\r\n"
                @"\r\n"];
            send(_clientSocket, mjpegHeader.UTF8String, mjpegHeader.length, 0);

            TVLog(@"[MJPEG] Stream started: q=%.2f scale=%.2f fps=%d maxW=%d maxH=%d",
                  mjpegQuality, mjpegScale, mjpegFps, mjpegMaxW, mjpegMaxH);

            // 持续推送 JPEG 帧
            NSTimeInterval frameInterval = 1.0 / mjpegFps;
            int frameCount = 0;
            BOOL useFramebuffer = [[TVNCApiManager sharedManager] isFramebufferAvailable];

            while (_server.isRunning) {
                @autoreleasepool {
                    // 获取当前帧
                    NSData *jpegData = nil;
                    if (useFramebuffer) {
                        jpegData = [[TVNCApiManager sharedManager]
                            captureScreenshotFromFramebufferWithFormat:@"jpeg"
                                                               quality:mjpegQuality
                                                                 scale:mjpegScale
                                                                  maxW:mjpegMaxW
                                                                  maxH:mjpegMaxH];
                        // 如果帧缓存突然不可用，降级
                        if (!jpegData) {
                            useFramebuffer = [[TVNCApiManager sharedManager] isFramebufferAvailable];
                        }
                    }
                    if (!jpegData) {
                        // 降级到普通截图
                        if (mjpegScale < 1.0) {
                            jpegData = [[TVNCApiManager sharedManager]
                                captureScreenshotWithFormat:@"jpeg"
                                                   quality:mjpegQuality
                                                  rotation:0
                                                     scale:mjpegScale];
                        } else {
                            jpegData = [[TVNCApiManager sharedManager]
                                captureScreenshotAsJPEGWithQuality:mjpegQuality];
                        }
                    }

                    if (jpegData) {
                        // 构建 MJPEG 帧
                        NSString *frameHeader = [NSString stringWithFormat:
                            @"--frameboundary\r\n"
                            @"Content-Type: image/jpeg\r\n"
                            @"Content-Length: %lu\r\n"
                            @"\r\n", (unsigned long)jpegData.length];
                        send(_clientSocket, frameHeader.UTF8String, frameHeader.length, 0);
                        send(_clientSocket, jpegData.bytes, jpegData.length, 0);
                        send(_clientSocket, "\r\n", 2, 0);

                        frameCount++;
                    }

                    // 等待下一帧
                    [NSThread sleepForTimeInterval:frameInterval];

                    // 检查连接是否还活着（非阻塞 recv 检测）
                    char peekBuf[1];
                    ssize_t peekResult = recv(_clientSocket, peekBuf, 1, MSG_PEEK | MSG_DONTWAIT);
                    if (peekResult == 0 || (peekResult < 0 && errno != EAGAIN && errno != EWOULDBLOCK)) {
                        // 客户端断开连接
                        TVLog(@"[MJPEG] Client disconnected after %d frames", frameCount);
                        break;
                    }
                }
            }

            close(_clientSocket);
            return;
        }
    }

    send_response: {
    NSMutableString *responseHeader = [NSMutableString string];
    [responseHeader appendFormat:@"HTTP/1.1 %ld OK\r\n", (long)response.statusCode];
    [responseHeader appendFormat:@"Content-Type: %@\r\n", response.contentType];
    [responseHeader appendFormat:@"Content-Length: %lu\r\n", (unsigned long)response.body.length];
    [responseHeader appendString:@"Access-Control-Allow-Origin: *\r\n"];
    [responseHeader appendString:@"Access-Control-Allow-Methods: GET, POST, OPTIONS, PROPFIND, MKCOL, PUT, DELETE, MOVE, COPY\r\n"];
    [responseHeader appendString:@"Access-Control-Allow-Headers: Content-Type, Content-Length, Accept, Accept-Language, Accept-Encoding, Destination, Overwrite, Depth\r\n"];
    [responseHeader appendString:@"Access-Control-Max-Age: 86400\r\n"];
    [responseHeader appendString:@"DAV: 1, 2\r\n"];
    [responseHeader appendString:@"Connection: close\r\n"];
    [responseHeader appendString:@"\r\n"];
    
    send(_clientSocket, responseHeader.UTF8String, responseHeader.length, 0);
    if (response.body.length > 0) {
        send(_clientSocket, response.body.bytes, response.body.length, 0);
    }
    
    close(_clientSocket);
    } // end send_response block
}

// POST /api/network/static_ip  (body JSON: {enabled: bool, ip, mask, router})
// daemon(root) 通过 SCPreferences 写入网络配置，巨魔版 App(mobile) 经此代理绕过沙盒限制。
- (TVNCHttpResponse *)handleNetworkStaticIP:(NSData *)body {
    TVNCHttpResponse *response = [[TVNCHttpResponse alloc] init];
    response.contentType = @"application/json";

    if (!body || body.length == 0) {
        response.statusCode = 400;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":@"Missing request body"} options:0 error:nil];
        return response;
    }
    NSError *jsonErr = nil;
    NSDictionary *req = [NSJSONSerialization JSONObjectWithData:body options:0 error:&jsonErr];
    if (!req || jsonErr) {
        response.statusCode = 400;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":@"Invalid JSON"} options:0 error:nil];
        return response;
    }

    BOOL enabled = [req[@"enabled"] boolValue];
    NSString *ip = [req[@"ip"] isKindOfClass:[NSString class]] ? req[@"ip"] : nil;
    NSString *mask = [req[@"mask"] isKindOfClass:[NSString class]] ? req[@"mask"] : @"";
    NSString *router = [req[@"router"] isKindOfClass:[NSString class]] ? req[@"router"] : @"";

    if (!ip || ip.length == 0) {
        response.statusCode = 400;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":@"Missing IP address"} options:0 error:nil];
        return response;
    }

    // SCPreferences write (root daemon)
    typedef struct __SCPreferences *SCPrefsRef;
    static SCPrefsRef (*_SCPCreate)(CFAllocatorRef, CFStringRef, CFStringRef, CFOptionFlags, CFErrorRef *) = NULL;
    static CFDictionaryRef (*_SCPPathGet)(SCPrefsRef, CFStringRef) = NULL;
    static Boolean (*_SCPPathSet)(SCPrefsRef, CFStringRef, CFPropertyListRef) = NULL;
    static Boolean (*_SCPCommit)(SCPrefsRef) = NULL;
    static Boolean (*_SCPApply)(SCPrefsRef) = NULL;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        void *h = dlopen("/System/Library/Frameworks/SystemConfiguration.framework/SystemConfiguration", RTLD_LAZY);
        if (h) {
            _SCPCreate  = dlsym(h, "SCPreferencesCreateWithOptions");
            _SCPPathGet = dlsym(h, "SCPreferencesPathGetValue");
            _SCPPathSet = dlsym(h, "SCPreferencesPathSetValue");
            _SCPCommit  = dlsym(h, "SCPreferencesCommitChanges");
            _SCPApply   = dlsym(h, "SCPreferencesApplyChanges");
        }
    });
    if (!_SCPCreate || !_SCPPathGet || !_SCPPathSet || !_SCPCommit || !_SCPApply) {
        response.statusCode = 500;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":@"SCPreferences API unavailable"} options:0 error:nil];
        return response;
    }

    CFErrorRef cfErr = NULL;
    SCPrefsRef prefs = _SCPCreate(kCFAllocatorDefault, CFSTR("TVNC-Net"), CFSTR("com.apple.SystemConfiguration"), (CFOptionFlags)1, &cfErr);
    if (!prefs) {
        NSString *msg = cfErr ? [(__bridge_transfer NSError *)cfErr localizedDescription] : @"Cannot open SystemConfiguration";
        response.statusCode = 500;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":msg} options:0 error:nil];
        return response;
    }

    NSDictionary *setup = (__bridge NSDictionary *)_SCPPathGet(prefs, CFSTR("Setup:/"));
    NSDictionary *services = setup[@"Network"] ? setup[@"Network"][@"Service"] : nil;
    if (!services || ![services isKindOfClass:[NSDictionary class]]) {
        CFRelease(prefs);
        response.statusCode = 500;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":@"No network services found"} options:0 error:nil];
        return response;
    }

    // 取默认路由接口
    NSString *targetIf = nil;
    {
        void *sc2 = dlopen("/System/Library/Frameworks/SystemConfiguration.framework/SystemConfiguration", RTLD_LAZY);
        if (sc2) {
            typeof(SCDynamicStoreCreate)* scCreate = (typeof(SCDynamicStoreCreate)*)dlsym(sc2, "SCDynamicStoreCreate");
            typeof(SCDynamicStoreCopyValue)* scCopy = (typeof(SCDynamicStoreCopyValue)*)dlsym(sc2, "SCDynamicStoreCopyValue");
            if (scCreate && scCopy) {
                SCDynamicStoreRef store = scCreate(NULL, CFSTR("TVNC-Net-If"), NULL, NULL);
                if (store) {
                    NSDictionary *ipv4 = (__bridge NSDictionary *)scCopy(store, CFSTR("State:/Network/Global/IPv4"));
                    targetIf = ipv4[@"PrimaryInterface"];
                    CFRelease(store);
                }
            }
        }
    }
    if (!targetIf) targetIf = @"en0";

    NSString *matchedID = nil;
    NSDictionary *matchedSvc = nil;
    for (NSString *sid in services) {
        NSDictionary *svc = services[sid];
        if (![svc isKindOfClass:[NSDictionary class]]) continue;
        NSString *dev = svc[@"Interface"] ? svc[@"Interface"][@"DeviceName"] : nil;
        if ([dev isKindOfClass:[NSString class]] && [dev isEqualToString:targetIf]) {
            matchedID = sid;
            matchedSvc = svc;
            break;
        }
    }
    if (!matchedID) {
        CFRelease(prefs);
        response.statusCode = 500;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":[NSString stringWithFormat:@"Service not found for %@", targetIf]} options:0 error:nil];
        return response;
    }

    NSString *setupPath = [NSString stringWithFormat:@"Setup:/Network/Service/%@", matchedID];
    NSDictionary *ipv4Section = matchedSvc[@"IPv4"];
    if (ipv4Section && [ipv4Section isKindOfClass:[NSDictionary class]]) {
        NSString *backupPath = [NSString stringWithFormat:@"State:/Network/TVNCBackup/%@", matchedID];
        _SCPPathSet(prefs, (__bridge CFStringRef)backupPath, (__bridge CFDictionaryRef)ipv4Section);
    }

    NSDictionary *currentIPv4 = [matchedSvc[@"IPv4"] isKindOfClass:[NSDictionary class]] ? matchedSvc[@"IPv4"] : @{};
    NSMutableDictionary *newIPv4 = [NSMutableDictionary dictionaryWithDictionary:currentIPv4];
    NSString *ipv4Path = [NSString stringWithFormat:@"%@/IPv4", setupPath];

    if (enabled) {
        newIPv4[@"ConfigMethod"] = @"Manual";
        newIPv4[@"Addresses"] = @[ip];
        newIPv4[@"SubnetMasks"] = @[mask.length ? mask : @"255.255.255.0"];
        if (router.length) newIPv4[@"Router"] = router;
        [newIPv4 removeObjectForKey:@"RouterHardwareAddress"];
    } else {
        newIPv4[@"ConfigMethod"] = @"DHCP";
        [newIPv4 removeObjectForKey:@"Addresses"];
        [newIPv4 removeObjectForKey:@"SubnetMasks"];
        [newIPv4 removeObjectForKey:@"Router"];
    }

    _SCPPathSet(prefs, (__bridge CFStringRef)ipv4Path, (__bridge CFDictionaryRef)newIPv4);

    if (!_SCPCommit(prefs) || !_SCPApply(prefs)) {
        CFRelease(prefs);
        response.statusCode = 500;
        response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@NO, @"error":@"Failed to commit configuration"} options:0 error:nil];
        return response;
    }
    CFRelease(prefs);

    response.statusCode = 200;
    response.body = [NSJSONSerialization dataWithJSONObject:@{@"success":@YES, @"interface":targetIf, @"enabled":@(enabled)} options:0 error:nil];
    return response;
}

@end
